insert into public.bible_verses (book_id, chapter, verse, text) values
  (58, 3, 5, 'Pour Moïse, il a été fidèle dans toute la maison de Dieu, comme serviteur, pour rendre témoignage de ce qui devait être annoncé;'),
  (58, 3, 6, 'mais Christ l''est comme Fils sur sa maison; et sa maison, c''est nous, pourvu que nous retenions jusqu''à la fin la ferme confiance et l''espérance dont nous nous glorifions.'),
  (58, 3, 7, 'C''est pourquoi, selon ce que dit le Saint-Esprit: Aujourd''hui, si vous entendez sa voix,'),
  (58, 3, 8, 'N''endurcissez pas vos cœurs, comme lors de la révolte, Le jour de la tentation dans le désert,'),
  (58, 3, 9, 'Où vos pères me tentèrent, Pour m''éprouver, et ils virent mes œuvres Pendant quarante ans.'),
  (58, 3, 10, 'Aussi je fus irrité contre cette génération, et je dis: Ils ont toujours un cœur qui s''égare. Ils n''ont pas connu mes voies.'),
  (58, 3, 11, 'Je jurai donc dans ma colère: Ils n''entreront pas dans mon repos!'),
  (58, 3, 12, 'Prenez garde, frères, que quelqu''un de vous n''ait un cœur mauvais et incrédule, au point de se détourner du Dieu vivant.'),
  (58, 3, 13, 'Mais exhortez-vous les uns les autres chaque jour, aussi longtemps qu''on peut dire: Aujourd''hui! afin qu''aucun de vous ne s''endurcisse par la séduction du péché.'),
  (58, 3, 14, 'Car nous sommes devenus participants de Christ, pourvu que nous retenions fermement jusqu''à la fin l''assurance que nous avions au commencement,'),
  (58, 3, 15, 'pendant qu''il est dit: Aujourd''hui, si vous entendez sa voix, N''endurcissez pas vos cœurs, comme lors de la révolte.'),
  (58, 3, 16, 'Qui furent, en effet, ceux qui se révoltèrent après l''avoir entendue, sinon tous ceux qui étaient sortis d''Égypte sous la conduite de Moïse?'),
  (58, 3, 17, 'Et contre qui Dieu fut-il irrité pendant quarante ans, sinon contre ceux qui péchaient, et dont les cadavres tombèrent dans le désert?'),
  (58, 3, 18, 'Et à qui jura-t-il qu''ils n''entreraient pas dans son repos, sinon à ceux qui avaient désobéi?'),
  (58, 3, 19, 'Aussi voyons-nous qu''ils ne purent y entrer à cause de leur incrédulité.'),
  (58, 4, 1, 'Craignons donc, tandis que la promesse d''entrer dans son repos subsiste encore, qu''aucun de vous ne paraisse être venu trop tard.'),
  (58, 4, 2, 'Car cette bonne nouvelle nous a été annoncée aussi bien qu''à eux; mais la parole qui leur fut annoncée ne leur servit de rien, parce qu''elle ne trouva pas de la foi chez ceux qui l''entendirent.'),
  (58, 4, 3, 'Pour nous qui avons cru, nous entrons dans le repos, selon qu''il dit: Je jurai dans ma colère: Ils n''entreront pas dans mon repos! Il dit cela, quoique ses œuvres eussent été achevées depuis la création du monde.'),
  (58, 4, 4, 'Car il a parlé quelque part ainsi du septième jour: Et Dieu se reposa de toutes ses œuvres le septième jour.'),
  (58, 4, 5, 'Et ici encore: Ils n''entreront pas dans mon repos!'),
  (58, 4, 6, 'Or, puisqu''il est encore réservé à quelques-uns d''y entrer, et que ceux à qui d''abord la promesse a été faite n''y sont pas entrés à cause de leur désobéissance,'),
  (58, 4, 7, 'Dieu fixe de nouveau un jour-aujourd''hui-en disant dans David si longtemps après, comme il est dit plus haut: Aujourd''hui, si vous entendez sa voix, N''endurcissez pas vos cœurs.'),
  (58, 4, 8, 'Car, si Josué leur eût donné le repos, il ne parlerait pas après cela d''un autre jour.'),
  (58, 4, 9, 'Il y a donc un repos de sabbat réservé au peuple de Dieu.'),
  (58, 4, 10, 'Car celui qui entre dans le repos de Dieu se repose de ses œuvres, comme Dieu s''est reposé des siennes.'),
  (58, 4, 11, 'Efforçons-nous donc d''entrer dans ce repos, afin que personne ne tombe en donnant le même exemple de désobéissance.'),
  (58, 4, 12, 'Car la parole de Dieu est vivante et efficace, plus tranchante qu''une épée quelconque à deux tranchants, pénétrante jusqu''à partager âme et esprit, jointures et moelles; elle juge les sentiments et les pensées du cœur.'),
  (58, 4, 13, 'Nulle créature n''est cachée devant lui, mais tout est à nu et à découvert aux yeux de celui à qui nous devons rendre compte.'),
  (58, 4, 14, 'Ainsi, puisque nous avons un grand souverain sacrificateur qui a traversé les cieux, Jésus, le Fils de Dieu, demeurons fermes dans la foi que nous professons.'),
  (58, 4, 15, 'Car nous n''avons pas un souverain sacrificateur qui ne puisse compatir à nos faiblesses; au contraire, il a été tenté comme nous en toutes choses, sans commettre de péché.'),
  (58, 4, 16, 'Approchons-nous donc avec assurance du trône de la grâce, afin d''obtenir miséricorde et de trouver grâce, pour être secourus dans nos besoins.'),
  (58, 5, 1, 'En effet, tout souverain sacrificateur pris du milieu des hommes est établi pour les hommes dans le service de Dieu, afin de présenter des offrandes et des sacrifices pour les péchés.'),
  (58, 5, 2, 'Il peut être indulgent pour les ignorants et les égarés, puisque la faiblesse est aussi son partage.'),
  (58, 5, 3, 'Et c''est à cause de cette faiblesse qu''il doit offrir des sacrifices pour ses propres péchés, comme pour ceux du peuple.'),
  (58, 5, 4, 'Nul ne s''attribue cette dignité, s''il n''est appelé de Dieu, comme le fut Aaron.'),
  (58, 5, 5, 'Et Christ ne s''est pas non plus attribué la gloire de devenir souverain sacrificateur, mais il la tient de celui qui lui a dit: Tu es mon Fils, Je t''ai engendré aujourd''hui!'),
  (58, 5, 6, 'Comme il dit encore ailleurs: Tu es sacrificateur pour toujours, Selon l''ordre de Melchisédek.'),
  (58, 5, 7, 'C''est lui qui, dans les jours de sa chair, ayant présenté avec de grands cris et avec larmes des prières et des supplications à celui qui pouvait le sauver de la mort, et ayant été exaucé à cause de sa piété,'),
  (58, 5, 8, 'a appris, bien qu''il fût Fils, l''obéissance par les choses qu''il a souffertes,'),
  (58, 5, 9, 'et qui, après avoir été élevé à la perfection, est devenu pour tous ceux qui lui obéissent l''auteur d''un salut éternel,'),
  (58, 5, 10, 'Dieu l''ayant déclaré souverain sacrificateur selon l''ordre de Melchisédek.'),
  (58, 5, 11, 'Nous avons beaucoup à dire là-dessus, et des choses difficiles à expliquer, parce que vous êtes devenus lents à comprendre.'),
  (58, 5, 12, 'Vous, en effet, qui depuis longtemps devriez être des maîtres, vous avez encore besoin qu''on vous enseigne les premiers rudiments des oracles de Dieu, vous en êtes venus à avoir besoin de lait et non d''une nourriture solide.'),
  (58, 5, 13, 'Or, quiconque en est au lait n''a pas l''expérience de la parole de justice; car il est un enfant.'),
  (58, 5, 14, 'Mais la nourriture solide est pour les hommes faits, pour ceux dont le jugement est exercé par l''usage à discerner ce qui est bien et ce qui est mal.'),
  (58, 6, 1, 'C''est pourquoi, laissant les éléments de la parole de Christ, tendons à ce qui est parfait, sans poser de nouveau le fondement du renoncement aux œuvres mortes, de la foi en Dieu,'),
  (58, 6, 2, 'de la doctrine des baptêmes, de l''imposition des mains, de la résurrection des morts, et du jugement éternel.'),
  (58, 6, 3, 'C''est ce que nous ferons, si Dieu le permet.'),
  (58, 6, 4, 'Car il est impossible que ceux qui ont été une fois éclairés, qui ont goûté le don céleste, qui ont eu part au Saint-Esprit,'),
  (58, 6, 5, 'qui ont goûté la bonne parole de Dieu et les puissances du siècle à venir,'),
  (58, 6, 6, 'et qui sont tombés, soient encore renouvelés et amenés à la repentance, puisqu''ils crucifient pour leur part le Fils de Dieu et l''exposent à l''ignominie.'),
  (58, 6, 7, 'Lorsqu''une terre est abreuvée par la pluie qui tombe souvent sur elle, et qu''elle produit une herbe utile à ceux pour qui elle est cultivée, elle participe à la bénédiction de Dieu;'),
  (58, 6, 8, 'mais, si elle produit des épines et des chardons, elle est réprouvée et près d''être maudite, et on finit par y mettre le feu.'),
  (58, 6, 9, 'Quoique nous parlions ainsi, bien-aimés, nous attendons, pour ce qui vous concerne, des choses meilleures et favorables au salut.'),
  (58, 6, 10, 'Car Dieu n''est pas injuste, pour oublier votre travail et l''amour que vous avez montré pour son nom, ayant rendu et rendant encore des services aux saints.'),
  (58, 6, 11, 'Nous désirons que chacun de vous montre le même zèle pour conserver jusqu''à la fin une pleine espérance,'),
  (58, 6, 12, 'en sorte que vous ne vous relâchiez point, et que vous imitiez ceux qui, par la foi et la persévérance, héritent des promesses.'),
  (58, 6, 13, 'Lorsque Dieu fit la promesse à Abraham, ne pouvant jurer par un plus grand que lui, il jura par lui-même,'),
  (58, 6, 14, 'et dit: Certainement je te bénirai et je multiplierai ta postérité.'),
  (58, 6, 15, 'Et c''est ainsi qu''Abraham, ayant persévéré, obtint l''effet de la promesse.'),
  (58, 6, 16, 'Or les hommes jurent par celui qui est plus grand qu''eux, et le serment est une garantie qui met fin à tous leurs différends.'),
  (58, 6, 17, 'C''est pourquoi Dieu, voulant montrer avec plus d''évidence aux héritiers de la promesse l''immutabilité de sa résolution, intervint par un serment,'),
  (58, 6, 18, 'afin que, par deux choses immuables, dans lesquelles il est impossible que Dieu mente, nous trouvions un puissant encouragement, nous dont le seul refuge a été de saisir l''espérance qui nous était proposée.'),
  (58, 6, 19, 'Cette espérance, nous la possédons comme une ancre de l''âme, sûre et solide; elle pénètre au delà du voile,'),
  (58, 6, 20, 'là où Jésus est entré pour nous comme précurseur, ayant été fait souverain sacrificateur pour toujours, selon l''ordre de Melchisédek.'),
  (58, 7, 1, 'En effet, ce Melchisédek, roi de Salem, sacrificateur du Dieu Très-Haut, -qui alla au-devant d''Abraham lorsqu''il revenait de la défaite des rois, qui le bénit,'),
  (58, 7, 2, 'et à qui Abraham donna la dîme de tout, -qui est d''abord roi de justice, d''après la signification de son nom, ensuite roi de Salem, c''est-à-dire roi de paix, -'),
  (58, 7, 3, 'qui est sans père, sans mère, sans généalogie, qui n''a ni commencement de jours ni fin de vie, -mais qui est rendu semblable au Fils de Dieu, -ce Melchisédek demeure sacrificateur à perpétuité.'),
  (58, 7, 4, 'Considérez combien est grand celui auquel le patriarche Abraham donna la dîme du butin.'),
  (58, 7, 5, 'Ceux des fils de Lévi qui exercent le sacerdoce ont, d''après la loi, l''ordre de lever la dîme sur le peuple, c''est-à-dire, sur leurs frères, qui cependant sont issus des reins d''Abraham;'),
  (58, 7, 6, 'et lui, qui ne tirait pas d''eux son origine, il leva la dîme sur Abraham, et il bénit celui qui avait les promesses.'),
  (58, 7, 7, 'Or c''est sans contredit l''inférieur qui est béni par le supérieur.'),
  (58, 7, 8, 'Et ici, ceux qui perçoivent la dîme sont des hommes mortels; mais là, c''est celui dont il est attesté qu''il est vivant.'),
  (58, 7, 9, 'De plus, Lévi, qui perçoit la dîme, l''a payée, pour ainsi dire, par Abraham;'),
  (58, 7, 10, 'car il était encore dans les reins de son père, lorsque Melchisédek alla au-devant d''Abraham.'),
  (58, 7, 11, 'Si donc la perfection avait été possible par le sacerdoce Lévitique, -car c''est sur ce sacerdoce que repose la loi donnée au peuple, -qu''était-il encore besoin qu''il parût un autre sacrificateur selon l''ordre de Melchisédek, et non selon l''ordre d''Aaron?'),
  (58, 7, 12, 'Car, le sacerdoce étant changé, nécessairement aussi il y a un changement de loi.'),
  (58, 7, 13, 'En effet, celui de qui ces choses sont dites appartient à une autre tribu, dont aucun membre n''a fait le service de l''autel;'),
  (58, 7, 14, 'car il est notoire que notre Seigneur est sorti de Juda, tribu dont Moïse n''a rien dit pour ce qui concerne le sacerdoce.'),
  (58, 7, 15, 'Cela devient plus évident encore, quand il paraît un autre sacrificateur à la ressemblance de Melchisédek,'),
  (58, 7, 16, 'institué, non d''après la loi d''une ordonnance charnelle, mais selon la puissance d''une vie impérissable;'),
  (58, 7, 17, 'car ce témoignage lui est rendu: Tu es sacrificateur pour toujours Selon l''ordre de Melchisédek.'),
  (58, 7, 18, 'Il y a ainsi abolition d''une ordonnance antérieure, à cause de son impuissance et de son inutilité,'),
  (58, 7, 19, '-car la loi n''a rien amené à la perfection, -et introduction d''une meilleure espérance, par laquelle nous nous approchons de Dieu.'),
  (58, 7, 20, 'Et, comme cela n''a pas eu lieu sans serment,'),
  (58, 7, 21, 'car, tandis que les Lévites sont devenus sacrificateurs sans serment, Jésus l''est devenu avec serment par celui qui lui a dit: Le Seigneur a juré, et il ne se repentira pas: Tu es sacrificateur pour toujours, Selon l''ordre de Melchisédek. -'),
  (58, 7, 22, 'Jésus est par cela même le garant d''une alliance plus excellente.'),
  (58, 7, 23, 'De plus, il y a eu des sacrificateurs en grand nombre, parce que la mort les empêchait d''être permanents.'),
  (58, 7, 24, 'Mais lui, parce qu''il demeure éternellement, possède un sacerdoce qui n''est pas transmissible.'),
  (58, 7, 25, 'C''est aussi pour cela qu''il peut sauver parfaitement ceux qui s''approchent de Dieu par lui, étant toujours vivant pour intercéder en leur faveur.'),
  (58, 7, 26, 'Il nous convenait, en effet, d''avoir un souverain sacrificateur comme lui, saint, innocent, sans tache, séparé des pécheurs, et plus élevé que les cieux,'),
  (58, 7, 27, 'qui n''a pas besoin, comme les souverains sacrificateurs, d''offrir chaque jour des sacrifices, d''abord pour ses propres péchés, ensuite pour ceux du peuple, -car ceci, il l''a fait une fois pour toutes en s''offrant lui-même.'),
  (58, 7, 28, 'En effet, la loi établit souverains sacrificateurs des hommes sujets à la faiblesse; mais la parole du serment qui a été fait après la loi établit le Fils, qui est parfait pour l''éternité.'),
  (58, 8, 1, 'Le point capital de ce qui vient d''être dit, c''est que nous avons un tel souverain sacrificateur, qui s''est assis à la droite du trône de la majesté divine dans les cieux,'),
  (58, 8, 2, 'comme ministre du sanctuaire et du véritable tabernacle, qui a été dressé par le Seigneur et non par un homme.'),
  (58, 8, 3, 'Tout souverain sacrificateur est établi pour présenter des offrandes et des sacrifices; d''où il est nécessaire que celui-ci ait aussi quelque chose à présenter.'),
  (58, 8, 4, 'S''il était sur la terre, il ne serait pas même sacrificateur, puisque là sont ceux qui présentent les offrandes selon la loi'),
  (58, 8, 5, '(lesquels célèbrent un culte, image et ombre des choses célestes, selon que Moïse en fut divinement averti lorsqu''il allait construire le tabernacle: Aie soin, lui fut-il dit, de faire tout d''après le modèle qui t''a été montré sur la montagne).'),
  (58, 8, 6, 'Mais maintenant il a obtenu un ministère d''autant supérieur qu''il est le médiateur d''une alliance plus excellente, qui a été établie sur de meilleures promesses.'),
  (58, 8, 7, 'En effet, si la première alliance avait été sans défaut, il n''aurait pas été question de la remplacer par une seconde.'),
  (58, 8, 8, 'Car c''est avec l''expression d''un blâme que le Seigneur dit à Israël: Voici, les jours viennent, dit le Seigneur, Où je ferai avec la maison d''Israël et la maison de Juda Une alliance nouvelle,'),
  (58, 8, 9, 'Non comme l''alliance que je traitai avec leurs pères, Le jour où je les saisis par la main Pour les faire sortir du pays d''Égypte; Car ils n''ont pas persévéré dans mon alliance, Et moi aussi je ne me suis pas soucié d''eux, dit le Seigneur.'),
  (58, 8, 10, 'Mais voici l''alliance que je ferai avec la maison d''Israël, Après ces jours-là, dit le Seigneur: Je mettrai mes lois dans leur esprit, Je les écrirai dans leur cœur; Et je serai leur Dieu, Et ils seront mon peuple.'),
  (58, 8, 11, 'Aucun n''enseignera plus son concitoyen, Ni aucun son frère, en disant: Connais le Seigneur! Car tous me connaîtront, Depuis le plus petit jusqu''au plus grand d''entre eux;'),
  (58, 8, 12, 'Parce que je pardonnerai leurs iniquités, Et que je ne me souviendrai plus de leurs péchés.'),
  (58, 8, 13, 'En disant: une alliance nouvelle, il a déclaré la première ancienne; or, ce qui est ancien, ce qui a vieilli, est près de disparaître.'),
  (58, 9, 1, 'La première alliance avait aussi des ordonnances relatives au culte, et le sanctuaire terrestre.'),
  (58, 9, 2, 'Un tabernacle fut, en effet, construit. Dans la partie antérieure, appelée le lieu saint, étaient le chandelier, la table, et les pains de proposition.'),
  (58, 9, 3, 'Derrière le second voile se trouvait la partie du tabernacle appelée le saint des saints,'),
  (58, 9, 4, 'renfermant l''autel d''or pour les parfums, et l''arche de l''alliance, entièrement recouverte d''or. Il y avait dans l''arche un vase d''or contenant la manne, la verge d''Aaron, qui avait fleuri, et les tables de l''alliance.'),
  (58, 9, 5, 'Au-dessus de l''arche étaient les chérubins de la gloire, couvrant de leur ombre le propitiatoire. Ce n''est pas le moment de parler en détail là-dessus.'),
  (58, 9, 6, 'Or, ces choses étant ainsi disposées, les sacrificateurs qui font le service entrent en tout temps dans la première partie du tabernacle;'),
  (58, 9, 7, 'et dans la seconde le souverain sacrificateur seul entre une fois par an, non sans y porter du sang qu''il offre pour lui-même et pour les péchés du peuple.'),
  (58, 9, 8, 'Le Saint-Esprit montrait par là que le chemin du lieu très saint n''était pas encore ouvert, tant que le premier tabernacle subsistait.'),
  (58, 9, 9, 'C''est une figure pour le temps actuel, où l''on présente des offrandes et des sacrifices qui ne peuvent rendre parfait sous le rapport de la conscience celui qui rend ce culte,'),
  (58, 9, 10, 'et qui, avec les aliments, les boissons et les diverses ablutions, étaient des ordonnances charnelles imposées seulement jusqu''à une époque de réformation.'),
  (58, 9, 11, 'Mais Christ est venu comme souverain sacrificateur des biens à venir; il a traversé le tabernacle plus grand et plus parfait, qui n''est pas construit de main d''homme, c''est-à-dire, qui n''est pas de cette création;'),
  (58, 9, 12, 'et il est entré une fois pour toutes dans le lieu très saint, non avec le sang des boucs et des veaux, mais avec son propre sang, ayant obtenu une rédemption éternelle.'),
  (58, 9, 13, 'Car si le sang des taureaux et des boucs, et la cendre d''une vache, répandue sur ceux qui sont souillés, sanctifient et procurent la pureté de la chair,'),
  (58, 9, 14, 'combien plus le sang de Christ, qui, par un esprit éternel, s''est offert lui-même sans tache à Dieu, purifiera-t-il votre conscience des œuvres mortes, afin que vous serviez le Dieu vivant!'),
  (58, 9, 15, 'Et c''est pour cela qu''il est le médiateur d''une nouvelle alliance, afin que, la mort étant intervenue pour le rachat des transgressions commises sous la première alliance, ceux qui ont été appelés reçoivent l''héritage éternel qui leur a été promis.'),
  (58, 9, 16, 'Car là où il y a un testament, il est nécessaire que la mort du testateur soit constatée.'),
  (58, 9, 17, 'Un testament, en effet, n''est valable qu''en cas de mort, puisqu''il n''a aucune force tant que le testateur vit.'),
  (58, 9, 18, 'Voilà pourquoi c''est avec du sang que même la première alliance fut inaugurée.'),
  (58, 9, 19, 'Moïse, après avoir prononcé devant tout le peuple tous les commandements de la loi, prit le sang des veaux et des boucs, avec de l''eau, de la laine écarlate, et de l''hysope; et il fit l''aspersion sur le livre lui-même et sur tout le peuple,'),
  (58, 9, 20, 'en disant: Ceci est le sang de l''alliance que Dieu a ordonnée pour vous.'),
  (58, 9, 21, 'Il fit pareillement l''aspersion avec le sang sur le tabernacle et sur tous les ustensiles du culte.'),
  (58, 9, 22, 'Et presque tout, d''après la loi, est purifié avec du sang, et sans effusion de sang il n''y a pas de pardon.'),
  (58, 9, 23, 'Il était donc nécessaire, puisque les images des choses qui sont dans les cieux devaient être purifiées de cette manière, que les choses célestes elles-mêmes le fussent par des sacrifices plus excellents que ceux-là.'),
  (58, 9, 24, 'Car Christ n''est pas entré dans un sanctuaire fait de main d''homme, en imitation du véritable, mais il est entré dans le ciel même, afin de comparaître maintenant pour nous devant la face de Dieu.'),
  (58, 9, 25, 'Et ce n''est pas pour s''offrir lui-même plusieurs fois qu''il y est entré, comme le souverain sacrificateur entre chaque année dans le sanctuaire avec du sang étranger;'),
  (58, 9, 26, 'autrement, il aurait fallu qu''il eût souffert plusieurs fois depuis la création du monde, tandis que maintenant, à la fin des siècles, il a paru une seule fois pour abolir le péché par son sacrifice.'),
  (58, 9, 27, 'Et comme il est réservé aux hommes de mourir une seule fois, après quoi vient le jugement,'),
  (58, 9, 28, 'de même Christ, qui s''est offert une seule fois pour porter les péchés de plusieurs, apparaîtra sans péché une seconde fois à ceux qui l''attendent pour leur salut.'),
  (58, 10, 1, 'En effet, la loi, qui possède une ombre des biens à venir, et non l''exacte représentation des choses, ne peut jamais, par les mêmes sacrifices qu''on offre perpétuellement chaque année, amener les assistants à la perfection.'),
  (58, 10, 2, 'Autrement, n''aurait-on pas cessé de les offrir, parce que ceux qui rendent ce culte, étant une fois purifiés, n''auraient plus eu aucune conscience de leurs péchés?'),
  (58, 10, 3, 'Mais le souvenir des péchés est renouvelé chaque année par ces sacrifices;'),
  (58, 10, 4, 'car il est impossible que le sang des taureaux et des boucs ôte les péchés.'),
  (58, 10, 5, 'C''est pourquoi Christ, entrant dans le monde, dit: Tu n''as voulu ni sacrifice ni offrande, Mais tu m''as formé un corps;'),
  (58, 10, 6, 'Tu n''as agréé ni holocaustes ni sacrifices pour le péché.'),
  (58, 10, 7, 'Alors j''ai dit: Voici, je viens (Dans le rouleau du livre il est question de moi) Pour faire, ô Dieu, ta volonté.'),
  (58, 10, 8, 'Après avoir dit d''abord: Tu n''as voulu et tu n''as agréé ni sacrifices ni offrandes, Ni holocaustes ni sacrifices pour le péché (ce qu''on offre selon la loi),'),
  (58, 10, 9, 'il dit ensuite: Voici, je viens Pour faire ta volonté. Il abolit ainsi la première chose pour établir la seconde.'),
  (58, 10, 10, 'C''est en vertu de cette volonté que nous sommes sanctifiés, par l''offrande du corps de Jésus-Christ, une fois pour toutes.'),
  (58, 10, 11, 'Et tandis que tout sacrificateur fait chaque jour le service et offre souvent les mêmes sacrifices, qui ne peuvent jamais ôter les péchés,'),
  (58, 10, 12, 'lui, après avoir offert un seul sacrifice pour les péchés, s''est assis pour toujours à la droite de Dieu,'),
  (58, 10, 13, 'attendant désormais que ses ennemis soient devenus son marchepied.'),
  (58, 10, 14, 'Car, par une seule offrande, il a amené à la perfection pour toujours ceux qui sont sanctifiés.'),
  (58, 10, 15, 'C''est ce que le Saint-Esprit nous atteste aussi; car, après avoir dit:'),
  (58, 10, 16, 'Voici l''alliance que je ferai avec eux, Après ces jours-là, dit le Seigneur: Je mettrai mes lois dans leurs cœurs, Et je les écrirai dans leur esprit, il ajoute:'),
  (58, 10, 17, 'Et je ne me souviendrai plus de leurs péchés ni de leurs iniquités.'),
  (58, 10, 18, 'Or, là où il y a pardon des péchés, il n''y a plus d''offrande pour le péché.'),
  (58, 10, 19, 'Ainsi donc, frères, puisque nous avons, au moyen du sang de Jésus, une libre entrée dans le sanctuaire'),
  (58, 10, 20, 'par la route nouvelle et vivante qu''il a inaugurée pour nous au travers du voile, c''est-à-dire, de sa chair,'),
  (58, 10, 21, 'et puisque nous avons un souverain sacrificateur établi sur la maison de Dieu,'),
  (58, 10, 22, 'approchons-nous avec un cœur sincère, dans la plénitude de la foi, les cœurs purifiés d''une mauvaise conscience, et le corps lavé d''une eau pure.'),
  (58, 10, 23, 'Retenons fermement la profession de notre espérance, car celui qui a fait la promesse est fidèle.'),
  (58, 10, 24, 'Veillons les uns sur les autres, pour nous exciter à la charité et aux bonnes œuvres.'),
  (58, 10, 25, 'N''abandonnons pas notre assemblée, comme c''est la coutume de quelques-uns; mais exhortons-nous réciproquement, et cela d''autant plus que vous voyez s''approcher le jour.'),
  (58, 10, 26, 'Car, si nous péchons volontairement après avoir reçu la connaissance de la vérité, il ne reste plus de sacrifice pour les péchés,'),
  (58, 10, 27, 'mais une attente terrible du jugement et l''ardeur d''un feu qui dévorera les rebelles.'),
  (58, 10, 28, 'Celui qui a violé la loi de Moïse meurt sans miséricorde, sur la déposition de deux ou de trois témoins;'),
  (58, 10, 29, 'de quel pire châtiment pensez-vous que sera jugé digne celui qui aura foulé aux pieds le Fils de Dieu, qui aura tenu pour profane le sang de l''alliance, par lequel il a été sanctifié, et qui aura outragé l''Esprit de la grâce?'),
  (58, 10, 30, 'Car nous connaissons celui qui a dit: A moi la vengeance, à moi la rétribution! et encore: Le Seigneur jugera son peuple.'),
  (58, 10, 31, 'C''est une chose terrible que de tomber entre les mains du Dieu vivant.'),
  (58, 10, 32, 'Souvenez-vous de ces premiers jours, où, après avoir été éclairés, vous avez soutenu un grand combat au milieu des souffrances,'),
  (58, 10, 33, 'd''une part, exposés comme en spectacle aux opprobres et aux tribulations, et de l''autre, vous associant à ceux dont la position était la même.'),
  (58, 10, 34, 'En effet, vous avez eu de la compassion pour les prisonniers, et vous avez accepté avec joie l''enlèvement de vos biens, sachant que vous avez des biens meilleurs et qui durent toujours.'),
  (58, 10, 35, 'N''abandonnez donc pas votre assurance, à laquelle est attachée une grande rémunération.'),
  (58, 10, 36, 'Car vous avez besoin de persévérance, afin qu''après avoir accompli la volonté de Dieu, vous obteniez ce qui vous est promis.'),
  (58, 10, 37, 'Encore un peu, un peu de temps: celui qui doit venir viendra, et il ne tardera pas.'),
  (58, 10, 38, 'Et mon juste vivra par la foi; mais, s''il se retire, mon âme ne prend pas plaisir en lui.'),
  (58, 10, 39, 'Nous, nous ne sommes pas de ceux qui se retirent pour se perdre, mais de ceux qui ont la foi pour sauver leur âme.'),
  (58, 11, 1, 'Or la foi est une ferme assurance des choses qu''on espère, une démonstration de celles qu''on ne voit pas.'),
  (58, 11, 2, 'Pour l''avoir possédée, les anciens ont obtenu un témoignage favorable.'),
  (58, 11, 3, 'C''est par la foi que nous reconnaissons que le monde a été formé par la parole de Dieu, en sorte que ce qu''on voit n''a pas été fait de choses visibles.'),
  (58, 11, 4, 'C''est par la foi qu''Abel offrit à Dieu un sacrifice plus excellent que celui de Caïn; c''est par elle qu''il fut déclaré juste, Dieu approuvant ses offrandes; et c''est par elle qu''il parle encore, quoique mort.'),
  (58, 11, 5, 'C''est par la foi qu''Énoch fut enlevé pour qu''il ne vît point la mort, et qu''il ne parut plus parce que Dieu l''avait enlevé; car, avant son enlèvement, il avait reçu le témoignage qu''il était agréable à Dieu.'),
  (58, 11, 6, 'Or sans la foi il est impossible de lui être agréable; car il faut que celui qui s''approche de Dieu croie que Dieu existe, et qu''il est le rémunérateur de ceux qui le cherchent.'),
  (58, 11, 7, 'C''est par la foi que Noé, divinement averti des choses qu''on ne voyait pas encore, et saisi d''une crainte respectueuse, construisit une arche pour sauver sa famille; c''est par elle qu''il condamna le monde, et devint héritier de la justice qui s''obtient par la foi.'),
  (58, 11, 8, 'C''est par la foi qu''Abraham, lors de sa vocation, obéit et partit pour un lieu qu''il devait recevoir en héritage, et qu''il partit sans savoir où il allait.'),
  (58, 11, 9, 'C''est par la foi qu''il vint s''établir dans la terre promise comme dans une terre étrangère, habitant sous des tentes, ainsi qu''Isaac et Jacob, les cohéritiers de la même promesse.'),
  (58, 11, 10, 'Car il attendait la cité qui a de solides fondements, celle dont Dieu est l''architecte et le constructeur.'),
  (58, 11, 11, 'C''est par la foi que Sara elle-même, malgré son âge avancé, fut rendue capable d''avoir une postérité, parce qu''elle crut à la fidélité de celui qui avait fait la promesse.'),
  (58, 11, 12, 'C''est pourquoi d''un seul homme, déjà usé de corps, naquit une postérité nombreuse comme les étoiles du ciel, comme le sable qui est sur le bord de la mer et qu''on ne peut compter.'),
  (58, 11, 13, 'C''est dans la foi qu''ils sont tous morts, sans avoir obtenu les choses promises; mais ils les ont vues et saluées de loin, reconnaissant qu''ils étaient étrangers et voyageurs sur la terre.'),
  (58, 11, 14, 'Ceux qui parlent ainsi montrent qu''ils cherchent une patrie.'),
  (58, 11, 15, 'S''ils avaient eu en vue celle d''où ils étaient sortis, ils auraient eu le temps d''y retourner.'),
  (58, 11, 16, 'Mais maintenant ils en désirent une meilleure, c''est-à-dire une céleste. C''est pourquoi Dieu n''a pas honte d''être appelé leur Dieu, car il leur a préparé une cité.'),
  (58, 11, 17, 'C''est par la foi qu''Abraham offrit Isaac, lorsqu''il fut mis à l''épreuve, et qu''il offrit son fils unique, lui qui avait reçu les promesses,'),
  (58, 11, 18, 'et à qui il avait été dit: En Isaac sera nommée pour toi une postérité.'),
  (58, 11, 19, 'Il pensait que Dieu est puissant, même pour ressusciter les morts; aussi le recouvra-t-il par une sorte de résurrection.'),
  (58, 11, 20, 'C''est par la foi qu''Isaac bénit Jacob et Ésaü, en vue des choses à venir.'),
  (58, 11, 21, 'C''est par la foi que Jacob mourant bénit chacun des fils de Joseph, et qu''il adora, appuyé sur l''extrémité de son bâton.'),
  (58, 11, 22, 'C''est par la foi que Joseph mourant fit mention de la sortie des fils d''Israël, et qu''il donna des ordres au sujet de ses os.'),
  (58, 11, 23, 'C''est par la foi que Moïse, à sa naissance, fut caché pendant trois mois par ses parents, parce qu''ils virent que l''enfant était beau, et qu''ils ne craignirent pas l''ordre du roi.'),
  (58, 11, 24, 'C''est par la foi que Moïse, devenu grand, refusa d''être appelé fils de la fille de Pharaon,'),
  (58, 11, 25, 'aimant mieux être maltraité avec le peuple de Dieu que d''avoir pour un temps la jouissance du péché,'),
  (58, 11, 26, 'regardant l''opprobre de Christ comme une richesse plus grande que les trésors de l''Égypte, car il avait les yeux fixés sur la rémunération.'),
  (58, 11, 27, 'C''est par la foi qu''il quitta l''Égypte, sans être effrayé de la colère du roi; car il se montra ferme, comme voyant celui qui est invisible.'),
  (58, 11, 28, 'C''est par la foi qu''il fit la Pâque et l''aspersion du sang, afin que l''exterminateur ne touchât pas aux premiers-nés des Israélites.'),
  (58, 11, 29, 'C''est par la foi qu''ils traversèrent la mer Rouge comme un lieu sec, tandis que les Égyptiens qui en firent la tentative furent engloutis.'),
  (58, 11, 30, 'C''est par la foi que les murailles de Jéricho tombèrent, après qu''on en eut fait le tour pendant sept jours.'),
  (58, 11, 31, 'C''est par la foi que Rahab la prostituée ne périt pas avec les rebelles, parce qu''elle avait reçu les espions avec bienveillance.'),
  (58, 11, 32, 'Et que dirai-je encore? Car le temps me manquerait pour parler de Gédéon, de Barak, de Samson, de Jephthé, de David, de Samuel, et des prophètes,'),
  (58, 11, 33, 'qui, par la foi, vainquirent des royaumes, exercèrent la justice, obtinrent des promesses, fermèrent la gueule des lions,'),
  (58, 11, 34, 'éteignirent la puissance du feu, échappèrent au tranchant de l''épée, guérirent de leurs maladies, furent vaillants à la guerre, mirent en fuite des armées étrangères.'),
  (58, 11, 35, 'Des femmes recouvrèrent leurs morts par la résurrection; d''autres furent livrés aux tourments, et n''acceptèrent point de délivrance, afin d''obtenir une meilleure résurrection;'),
  (58, 11, 36, 'd''autres subirent les moqueries et le fouet, les chaînes et la prison;'),
  (58, 11, 37, 'ils furent lapidés, sciés, torturés, ils moururent tués par l''épée, ils allèrent çà et là vêtus de peaux de brebis et de peaux de chèvres, dénués de tout, persécutés, maltraités,'),
  (58, 11, 38, 'eux dont le monde n''était pas digne, errants dans les déserts et les montagnes, dans les cavernes et les antres de la terre.'),
  (58, 11, 39, 'Tous ceux-là, à la foi desquels il a été rendu témoignage, n''ont pas obtenu ce qui leur était promis,'),
  (58, 11, 40, 'Dieu ayant en vue quelque chose de meilleur pour nous, afin qu''ils ne parvinssent pas sans nous à la perfection.'),
  (58, 12, 1, 'Nous donc aussi, puisque nous sommes environnés d''une si grande nuée de témoins, rejetons tout fardeau, et le péché qui nous enveloppe si facilement, et courons avec persévérance dans la carrière qui nous est ouverte,'),
  (58, 12, 2, 'ayant les regards sur Jésus, le chef et le consommateur de la foi, qui, en vue de la joie qui lui était réservée, a souffert la croix, méprisé l''ignominie, et s''est assis à la droite du trône de Dieu.'),
  (58, 12, 3, 'Considérez, en effet, celui qui a supporté contre sa personne une telle opposition de la part des pécheurs, afin que vous ne vous lassiez point, l''âme découragée.'),
  (58, 12, 4, 'Vous n''avez pas encore résisté jusqu''au sang, en luttant contre le péché.'),
  (58, 12, 5, 'Et vous avez oublié l''exhortation qui vous est adressée comme à des fils: Mon fils, ne méprise pas le châtiment du Seigneur, Et ne perds pas courage lorsqu''il te reprend;'),
  (58, 12, 6, 'Car le Seigneur châtie celui qu''il aime, Et il frappe de la verge tous ceux qu''il reconnaît pour ses fils.'),
  (58, 12, 7, 'Supportez le châtiment: c''est comme des fils que Dieu vous traite; car quel est le fils qu''un père ne châtie pas?'),
  (58, 12, 8, 'Mais si vous êtes exempts du châtiment auquel tous ont part, vous êtes donc des enfants illégitimes, et non des fils.'),
  (58, 12, 9, 'D''ailleurs, puisque nos pères selon la chair nous ont châtiés, et que nous les avons respectés, ne devons-nous pas à bien plus forte raison nous soumettre au Père des esprits, pour avoir la vie?'),
  (58, 12, 10, 'Nos pères nous châtiaient pour peu de jours, comme ils le trouvaient bon; mais Dieu nous châtie pour notre bien, afin que nous participions à sa sainteté.'),
  (58, 12, 11, 'Il est vrai que tout châtiment semble d''abord un sujet de tristesse, et non de joie; mais il produit plus tard pour ceux qui ont été ainsi exercés un fruit paisible de justice.'),
  (58, 12, 12, 'Fortifiez donc vos mains languissantes Et vos genoux affaiblis;'),
  (58, 12, 13, 'et suivez avec vos pieds des voies droites, afin que ce qui est boiteux ne dévie pas, mais plutôt se raffermisse.'),
  (58, 12, 14, 'Recherchez la paix avec tous, et la sanctification, sans laquelle personne ne verra le Seigneur.'),
  (58, 12, 15, 'Veillez à ce que nul ne se prive de la grâce de Dieu; à ce qu''aucune racine d''amertume, poussant des rejetons, ne produise du trouble, et que plusieurs n''en soient infectés;'),
  (58, 12, 16, 'à ce qu''il n''y ait ni impudique, ni profane comme Ésaü, qui pour un mets vendit son droit d''aînesse.'),
  (58, 12, 17, 'Vous savez que, plus tard, voulant obtenir la bénédiction, il fut rejeté, quoiqu''il la sollicitât avec larmes; car son repentir ne put avoir aucun effet.'),
  (58, 12, 18, 'Vous ne vous êtes pas approchés d''une montagne qu''on pouvait toucher et qui était embrasée par le feu, ni de la nuée, ni des ténèbres, ni de la tempête,'),
  (58, 12, 19, 'ni du retentissement de la trompette, ni du bruit des paroles, tel que ceux qui l''entendirent demandèrent qu''il ne leur en fût adressé aucune de plus,'),
  (58, 12, 20, 'car ils ne supportaient pas cette déclaration: Si même une bête touche la montagne, elle sera lapidée.'),
  (58, 12, 21, 'Et ce spectacle était si terrible que Moïse dit: Je suis épouvanté et tout tremblant!'),
  (58, 12, 22, 'Mais vous vous êtes approchés de la montagne de Sion, de la cité du Dieu vivant, la Jérusalem céleste, des myriades qui forment le chœur des anges,'),
  (58, 12, 23, 'de l''assemblée des premiers-nés inscrits dans les cieux, du juge qui est le Dieu de tous, des esprits des justes parvenus à la perfection,'),
  (58, 12, 24, 'de Jésus qui est le médiateur de la nouvelle alliance, et du sang de l''aspersion qui parle mieux que celui d''Abel.'),
  (58, 12, 25, 'Gardez-vous de refuser d''entendre celui qui parle; car si ceux-là n''ont pas échappé qui refusèrent d''entendre celui qui publiait les oracles sur la terre, combien moins échapperons-nous, si nous nous détournons de celui qui parle du haut des cieux,'),
  (58, 12, 26, 'lui, dont la voix alors ébranla la terre, et qui maintenant a fait cette promesse: Une fois encore j''ébranlerai non seulement la terre, mais aussi le ciel.'),
  (58, 12, 27, 'Ces mots: Une fois encore, indiquent le changement des choses ébranlées, comme étant faites pour un temps, afin que les choses inébranlables subsistent.'),
  (58, 12, 28, 'C''est pourquoi, recevant un royaume inébranlable, montrons notre reconnaissance en rendant à Dieu un culte qui lui soit agréable, avec piété et avec crainte,'),
  (58, 12, 29, 'car notre Dieu est aussi un feu dévorant.'),
  (58, 13, 1, 'Persévérez dans l''amour fraternel.'),
  (58, 13, 2, 'N''oubliez pas l''hospitalité; car, en l''exerçant, quelques-uns ont logé des anges, sans le savoir.'),
  (58, 13, 3, 'Souvenez-vous des prisonniers, comme si vous étiez aussi prisonniers; de ceux qui sont maltraités, comme étant aussi vous-mêmes dans un corps.'),
  (58, 13, 4, 'Que le mariage soit honoré de tous, et le lit conjugal exempt de souillure, car Dieu jugera les impudiques et les adultères.'),
  (58, 13, 5, 'Ne vous livrez pas à l''amour de l''argent; contentez-vous de ce que vous avez; car Dieu lui-même a dit: Je ne te délaisserai point, et je ne t''abandonnerai point.'),
  (58, 13, 6, 'C''est donc avec assurance que nous pouvons dire: Le Seigneur est mon aide, je ne craindrai rien; Que peut me faire un homme?'),
  (58, 13, 7, 'Souvenez-vous de vos conducteurs qui vous ont annoncé la parole de Dieu; considérez quelle a été la fin de leur vie, et imitez leur foi.'),
  (58, 13, 8, 'Jésus-Christ est le même hier, aujourd''hui, et éternellement.'),
  (58, 13, 9, 'Ne vous laissez pas entraîner par des doctrines diverses et étrangères; car il est bon que le cœur soit affermi par la grâce, et non par des aliments qui n''ont servi de rien à ceux qui s''y sont attachés.'),
  (58, 13, 10, 'Nous avons un autel dont ceux qui font le service au tabernacle n''ont pas le pouvoir de manger.'),
  (58, 13, 11, 'Les corps des animaux, dont le sang est porté dans le sanctuaire par le souverain sacrificateur pour le péché, sont brûlés hors du camp.'),
  (58, 13, 12, 'C''est pour cela que Jésus aussi, afin de sanctifier le peuple par son propre sang, a souffert hors de la porte.'),
  (58, 13, 13, 'Sortons donc pour aller à lui, hors du camp, en portant son opprobre.'),
  (58, 13, 14, 'Car nous n''avons point ici-bas de cité permanente, mais nous cherchons celle qui est à venir.'),
  (58, 13, 15, 'Par lui, offrons sans cesse à Dieu un sacrifice de louange, c''est-à-dire le fruit de lèvres qui confessent son nom.'),
  (58, 13, 16, 'Et n''oubliez pas la bienfaisance et la libéralité, car c''est à de tels sacrifices que Dieu prend plaisir.'),
  (58, 13, 17, 'Obéissez à vos conducteurs et ayez pour eux de la déférence, car ils veillent sur vos âmes comme devant en rendre compte; qu''il en soit ainsi, afin qu''ils le fassent avec joie, et non en gémissant, ce qui ne vous serait d''aucun avantage.'),
  (58, 13, 18, 'Priez pour nous; car nous croyons avoir une bonne conscience, voulant en toutes choses nous bien conduire.'),
  (58, 13, 19, 'C''est avec instance que je vous demande de le faire, afin que je vous sois rendu plus tôt.'),
  (58, 13, 20, 'Que le Dieu de paix, qui a ramené d''entre les morts le grand pasteur des brebis, par le sang d''une alliance éternelle, notre Seigneur Jésus,'),
  (58, 13, 21, 'vous rende capables de toute bonne œuvre pour l''accomplissement de sa volonté, et fasse en vous ce qui lui est agréable, par Jésus-Christ, auquel soit la gloire aux siècles des siècles! Amen!'),
  (58, 13, 22, 'Je vous prie, frères, de supporter ces paroles d''exhortation, car je vous ai écrit brièvement.'),
  (58, 13, 23, 'Sachez que notre frère Timothée a été relâché; s''il vient bientôt, j''irai vous voir avec lui.'),
  (58, 13, 24, 'Saluez tous vos conducteurs, et tous les saints. Ceux d''Italie vous saluent.'),
  (58, 13, 25, 'Que la grâce soit avec vous tous! Amen!'),
  (59, 1, 1, 'Jacques, serviteur de Dieu et du Seigneur Jésus-Christ, aux douze tribus qui sont dans la dispersion, salut!'),
  (59, 1, 2, 'Mes frères, regardez comme un sujet de joie complète les diverses épreuves auxquelles vous pouvez être exposés,'),
  (59, 1, 3, 'sachant que l''épreuve de votre foi produit la patience.'),
  (59, 1, 4, 'Mais il faut que la patience accomplisse parfaitement son œuvre, afin que vous soyez parfaits et accomplis, sans faillir en rien.'),
  (59, 1, 5, 'Si quelqu''un d''entre vous manque de sagesse, qu''il la demande à Dieu, qui donne à tous simplement et sans reproche, et elle lui sera donnée.'),
  (59, 1, 6, 'Mais qu''il la demande avec foi, sans douter; car celui qui doute est semblable au flot de la mer, agité par le vent et poussé de côté et d''autre.'),
  (59, 1, 7, 'Qu''un tel homme ne s''imagine pas qu''il recevra quelque chose du Seigneur:'),
  (59, 1, 8, 'c''est un homme irrésolu, inconstant dans toutes ses voies.'),
  (59, 1, 9, 'Que le frère de condition humble se glorifie de son élévation.'),
  (59, 1, 10, 'Que le riche, au contraire, se glorifie de son humiliation; car il passera comme la fleur de l''herbe.'),
  (59, 1, 11, 'Le soleil s''est levé avec sa chaleur ardente, il a desséché l''herbe, sa fleur est tombée, et la beauté de son aspect a disparu: ainsi le riche se flétrira dans ses entreprises.'),
  (59, 1, 12, 'Heureux l''homme qui supporte patiemment la tentation; car, après avoir été éprouvé, il recevra la couronne de vie, que le Seigneur a promise à ceux qui l''aiment.'),
  (59, 1, 13, 'Que personne, lorsqu''il est tenté, ne dise: C''est Dieu qui me tente. Car Dieu ne peut être tenté par le mal, et il ne tente lui-même personne.'),
  (59, 1, 14, 'Mais chacun est tenté quand il est attiré et amorcé par sa propre convoitise.'),
  (59, 1, 15, 'Puis la convoitise, lorsqu''elle a conçu, enfante le péché; et le péché, étant consommé, produit la mort.'),
  (59, 1, 16, 'Ne vous y trompez pas, mes frères bien-aimés:'),
  (59, 1, 17, 'toute grâce excellente et tout don parfait descendent d''en haut, du Père des lumières, chez lequel il n''y a ni changement ni ombre de variation.'),
  (59, 1, 18, 'Il nous a engendrés selon sa volonté, par la parole de vérité, afin que nous soyons en quelque sorte les prémices de ses créatures.'),
  (59, 1, 19, 'Sachez-le, mes frères bien-aimés. Ainsi, que tout homme soit prompt à écouter, lent à parler, lent à se mettre en colère;'),
  (59, 1, 20, 'car la colère de l''homme n''accomplit pas la justice de Dieu.'),
  (59, 1, 21, 'C''est pourquoi, rejetant toute souillure et tout excès de malice, recevez avec douceur la parole qui a été plantée en vous, et qui peut sauver vos âmes.'),
  (59, 1, 22, 'Mettez en pratique la parole, et ne vous bornez pas à l''écouter, en vous trompant vous-mêmes par de faux raisonnements.'),
  (59, 1, 23, 'Car, si quelqu''un écoute la parole et ne la met pas en pratique, il est semblable à un homme qui regarde dans un miroir son visage naturel,'),
  (59, 1, 24, 'et qui, après s''être regardé, s''en va, et oublie aussitôt quel il était.'),
  (59, 1, 25, 'Mais celui qui aura plongé les regards dans la loi parfaite, la loi de la liberté, et qui aura persévéré, n''étant pas un auditeur oublieux, mais se mettant à l''œuvre, celui-là sera heureux dans son activité.'),
  (59, 1, 26, 'Si quelqu''un croit être religieux, sans tenir sa langue en bride, mais en trompant son cœur, la religion de cet homme est vaine.'),
  (59, 1, 27, 'La religion pure et sans tache, devant Dieu notre Père, consiste à visiter les orphelins et les veuves dans leurs afflictions, et à se préserver des souillures du monde.'),
  (59, 2, 1, 'Mes frères, que votre foi en notre glorieux Seigneur Jésus-Christ soit exempte de toute acception de personnes.'),
  (59, 2, 2, 'Supposez, en effet, qu''il entre dans votre assemblée un homme avec un anneau d''or et un habit magnifique, et qu''il y entre aussi un pauvre misérablement vêtu;'),
  (59, 2, 3, 'si, tournant vos regards vers celui qui porte l''habit magnifique, vous lui dites: Toi, assieds-toi ici à cette place d''honneur! et si vous dites au pauvre: Toi, tiens-toi là debout! ou bien: Assieds-toi au-dessous de mon marchepied!'),
  (59, 2, 4, 'ne faites-vous pas en vous-mêmes une distinction, et ne jugez-vous pas sous l''inspiration de pensées mauvaises?'),
  (59, 2, 5, 'Écoutez, mes frères bien-aimés: Dieu n''a-t-il pas choisi les pauvres aux yeux du monde, pour qu''ils soient riches en la foi, et héritiers du royaume qu''il a promis à ceux qui l''aiment?'),
  (59, 2, 6, 'Et vous, vous avilissez le pauvre! Ne sont-ce pas les riches qui vous oppriment, et qui vous traînent devant les tribunaux?'),
  (59, 2, 7, 'Ne sont-ce pas eux qui outragent le beau nom que vous portez?'),
  (59, 2, 8, 'Si vous accomplissez la loi royale, selon l''Écriture: Tu aimeras ton prochain comme toi-même, vous faites bien.'),
  (59, 2, 9, 'Mais si vous faites acception de personnes, vous commettez un péché, vous êtes condamnés par la loi comme des transgresseurs.'),
  (59, 2, 10, 'Car quiconque observe toute la loi, mais pèche contre un seul commandement, devient coupable de tous.'),
  (59, 2, 11, 'En effet, celui qui a dit: Tu ne commettras point d''adultère, a dit aussi: Tu ne tueras point. Or, si tu ne commets point d''adultère, mais que tu commettes un meurtre, tu deviens transgresseur de la loi.'),
  (59, 2, 12, 'Parlez et agissez comme devant être jugés par une loi de liberté,'),
  (59, 2, 13, 'car le jugement est sans miséricorde pour qui n''a pas fait miséricorde. La miséricorde triomphe du jugement.'),
  (59, 2, 14, 'Mes frères, que sert-il à quelqu''un de dire qu''il a la foi, s''il n''a pas les œuvres? La foi peut-elle le sauver?'),
  (59, 2, 15, 'Si un frère ou une sœur sont nus et manquent de la nourriture de chaque jour,'),
  (59, 2, 16, 'et que l''un d''entre vous leur dise: Allez en paix, chauffez-vous et vous rassasiez! et que vous ne leur donniez pas ce qui est nécessaire au corps, à quoi cela sert-il?'),
  (59, 2, 17, 'Il en est ainsi de la foi: si elle n''a pas les œuvres, elle est morte en elle-même.'),
  (59, 2, 18, 'Mais quelqu''un dira: Toi, tu as la foi; et moi, j''ai les œuvres. Montre-moi ta foi sans les œuvres, et moi, je te montrerai la foi par mes œuvres.'),
  (59, 2, 19, 'Tu crois qu''il y a un seul Dieu, tu fais bien; les démons le croient aussi, et ils tremblent.'),
  (59, 2, 20, 'Veux-tu savoir, ô homme vain, que la foi sans les œuvres est inutile?'),
  (59, 2, 21, 'Abraham, notre père, ne fut-il pas justifié par les œuvres, lorsqu''il offrit son fils Isaac sur l''autel?'),
  (59, 2, 22, 'Tu vois que la foi agissait avec ses œuvres, et que par les œuvres la foi fut rendue parfaite.'),
  (59, 2, 23, 'Ainsi s''accomplit ce que dit l''Écriture: Abraham crut à Dieu, et cela lui fut imputé à justice; et il fut appelé ami de Dieu.'),
  (59, 2, 24, 'Vous voyez que l''homme est justifié par les œuvres, et non par la foi seulement.'),
  (59, 2, 25, 'Rahab la prostituée ne fut-elle pas également justifiée par les œuvres, lorsqu''elle reçut les messagers et qu''elle les fit partir par un autre chemin?'),
  (59, 2, 26, 'Comme le corps sans âme est mort, de même la foi sans les œuvres est morte.'),
  (59, 3, 1, 'Mes frères, qu''il n''y ait pas parmi vous un grand nombre de personnes qui se mettent à enseigner, car vous savez que nous serons jugés plus sévèrement.'),
  (59, 3, 2, 'Nous bronchons tous de plusieurs manières. Si quelqu''un ne bronche point en paroles, c''est un homme parfait, capable de tenir tout son corps en bride.'),
  (59, 3, 3, 'Si nous mettons le mors dans la bouche des chevaux pour qu''ils nous obéissent, nous dirigeons aussi leur corps tout entier.'),
  (59, 3, 4, 'Voici, même les navires, qui sont si grands et que poussent des vents impétueux, sont dirigés par un très petit gouvernail, au gré du pilote.'),
  (59, 3, 5, 'De même, la langue est un petit membre, et elle se vante de grandes choses. Voici, comme un petit feu peut embraser une grande forêt!'),
  (59, 3, 6, 'La langue aussi est un feu; c''est le monde de l''iniquité. La langue est placée parmi nos membres, souillant tout le corps, et enflammant le cours de la vie, étant elle-même enflammée par la géhenne.'),
  (59, 3, 7, 'Toutes les espèces de bêtes et d''oiseaux, de reptiles et d''animaux marins, sont domptés et ont été domptés par la nature humaine;'),
  (59, 3, 8, 'mais la langue, aucun homme ne peut la dompter; c''est un mal qu''on ne peut réprimer; elle est pleine d''un venin mortel.'),
  (59, 3, 9, 'Par elle nous bénissons le Seigneur notre Père, et par elle nous maudissons les hommes faits à l''image de Dieu.'),
  (59, 3, 10, 'De la même bouche sortent la bénédiction et la malédiction. Il ne faut pas, mes frères, qu''il en soit ainsi.'),
  (59, 3, 11, 'La source fait-elle jaillir par la même ouverture l''eau douce et l''eau amère?'),
  (59, 3, 12, 'Un figuier, mes frères, peut-il produire des olives, ou une vigne des figues? De l''eau salée ne peut pas non plus produire de l''eau douce.'),
  (59, 3, 13, 'Lequel d''entre vous est sage et intelligent? Qu''il montre ses œuvres par une bonne conduite avec la douceur de la sagesse.'),
  (59, 3, 14, 'Mais si vous avez dans votre cœur un zèle amer et un esprit de dispute, ne vous glorifiez pas et ne mentez pas contre la vérité.'),
  (59, 3, 15, 'Cette sagesse n''est point celle qui vient d''en haut; mais elle est terrestre, charnelle, diabolique.'),
  (59, 3, 16, 'Car là où il y a un zèle amer et un esprit de dispute, il y a du désordre et toutes sortes de mauvaises actions.'),
  (59, 3, 17, 'La sagesse d''en haut est premièrement pure, ensuite pacifique, modérée, conciliante, pleine de miséricorde et de bons fruits, exempte de duplicité, d''hypocrisie.'),
  (59, 3, 18, 'Le fruit de la justice est semé dans la paix par ceux qui recherchent la paix.'),
  (59, 4, 1, 'D''où viennent les luttes, et d''où viennent les querelles parmi vous? N''est-ce pas de vos passions qui combattent dans vos membres?'),
  (59, 4, 2, 'Vous convoitez, et vous ne possédez pas; vous êtes meurtriers et envieux, et vous ne pouvez pas obtenir; vous avez des querelles et des luttes, et vous ne possédez pas, parce que vous ne demandez pas.'),
  (59, 4, 3, 'Vous demandez, et vous ne recevez pas, parce que vous demandez mal, dans le but de satisfaire vos passions.'),
  (59, 4, 4, 'Adultères que vous êtes! ne savez-vous pas que l''amour du monde est inimitié contre Dieu? Celui donc qui veut être ami du monde se rend ennemi de Dieu.'),
  (59, 4, 5, 'Croyez-vous que l''Écriture parle en vain? C''est avec jalousie que Dieu chérit l''esprit qu''il a fait habiter en nous.'),
  (59, 4, 6, 'Il accorde, au contraire, une grâce plus excellente; c''est pourquoi l''Écriture dit: Dieu résiste aux orgueilleux, Mais il fait grâce aux humbles.'),
  (59, 4, 7, 'Soumettez-vous donc à Dieu; résistez au diable, et il fuira loin de vous.'),
  (59, 4, 8, 'Approchez-vous de Dieu, et il s''approchera de vous. Nettoyez vos mains, pécheurs; purifiez vos cœurs, hommes irrésolus.'),
  (59, 4, 9, 'Sentez votre misère; soyez dans le deuil et dans les larmes; que votre rire se change en deuil, et votre joie en tristesse.'),
  (59, 4, 10, 'Humiliez-vous devant le Seigneur, et il vous élèvera.'),
  (59, 4, 11, 'Ne parlez point mal les uns des autres, frères. Celui qui parle mal d''un frère, ou qui juge son frère, parle mal de la loi et juge la loi. Or, si tu juges la loi, tu n''es pas observateur de la loi, mais tu en es juge.'),
  (59, 4, 12, 'Un seul est législateur et juge, c''est celui qui peut sauver et perdre; mais toi, qui es-tu, qui juges le prochain?'),
  (59, 4, 13, 'A vous maintenant, qui dites: Aujourd''hui ou demain nous irons dans telle ville, nous y passerons une année, nous trafiquerons, et nous gagnerons!'),
  (59, 4, 14, 'Vous qui ne savez pas ce qui arrivera demain! car, qu''est-ce que votre vie? Vous êtes une vapeur qui paraît pour un peu de temps, et qui ensuite disparaît.'),
  (59, 4, 15, 'Vous devriez dire, au contraire: Si Dieu le veut, nous vivrons, et nous ferons ceci ou cela.'),
  (59, 4, 16, 'Mais maintenant vous vous glorifiez dans vos pensées orgueilleuses. C''est chose mauvaise que de se glorifier de la sorte.'),
  (59, 4, 17, 'Celui donc qui sait faire ce qui est bien, et qui ne le fait pas, commet un péché.'),
  (59, 5, 1, 'A vous maintenant, riches! Pleurez et gémissez, à cause des malheurs qui viendront sur vous.'),
  (59, 5, 2, 'Vos richesses sont pourries, et vos vêtements sont rongés par les teignes.'),
  (59, 5, 3, 'Votre or et votre argent sont rouillés; et leur rouille s''élèvera en témoignage contre vous, et dévorera vos chairs comme un feu. Vous avez amassé des trésors dans les derniers jours!'),
  (59, 5, 4, 'Voici, le salaire des ouvriers qui ont moissonné vos champs, et dont vous les avez frustrés, crie, et les cris des moissonneurs sont parvenus jusqu''aux oreilles du Seigneur des armées.'),
  (59, 5, 5, 'Vous avez vécu sur la terre dans les voluptés et dans les délices, vous avez rassasié vos cœurs au jour du carnage.'),
  (59, 5, 6, 'Vous avez condamné, vous avez tué le juste, qui ne vous a pas résisté.'),
  (59, 5, 7, 'Soyez donc patients, frères jusqu''à l''avènement du Seigneur. Voici, le laboureur attend le précieux fruit de la terre, prenant patience à son égard, jusqu''à ce qu''il ait reçu les pluies de la première et de l''arrière-saison.'),
  (59, 5, 8, 'Vous aussi, soyez patients, affermissez vos cœurs, car l''avènement du Seigneur est proche.'),
  (59, 5, 9, 'Ne vous plaignez pas les uns des autres, frères, afin que vous ne soyez pas jugés: voici, le juge est à la porte.'),
  (59, 5, 10, 'Prenez, mes frères, pour modèles de souffrance et de patience les prophètes qui ont parlé au nom du Seigneur.'),
  (59, 5, 11, 'Voici, nous disons bienheureux ceux qui ont souffert patiemment. Vous avez entendu parler de la patience de Job, et vous avez vu la fin que le Seigneur lui accorda, car le Seigneur est plein de miséricorde et de compassion.'),
  (59, 5, 12, 'Avant toutes choses, mes frères, ne jurez ni par le ciel, ni par la terre, ni par aucun autre serment. Mais que votre oui soit oui, et que votre non soit non, afin que vous ne tombiez pas sous le jugement.'),
  (59, 5, 13, 'Quelqu''un parmi vous est-il dans la souffrance? Qu''il prie. Quelqu''un est-il dans la joie? Qu''il chante des cantiques.'),
  (59, 5, 14, 'Quelqu''un parmi vous est-il malade? Qu''il appelle les anciens de l''Église, et que les anciens prient pour lui, en l''oignant d''huile au nom du Seigneur;'),
  (59, 5, 15, 'la prière de la foi sauvera le malade, et le Seigneur le relèvera; et s''il a commis des péchés, il lui sera pardonné.'),
  (59, 5, 16, 'Confessez donc vos péchés les uns aux autres, et priez les uns pour les autres, afin que vous soyez guéris. La prière fervente du juste a une grande efficace.'),
  (59, 5, 17, 'Élie était un homme de la même nature que nous: il pria avec instance pour qu''il ne plût point, et il ne tomba point de pluie sur la terre pendant trois ans et six mois.'),
  (59, 5, 18, 'Puis il pria de nouveau, et le ciel donna de la pluie, et la terre produisit son fruit.'),
  (59, 5, 19, 'Mes frères, si quelqu''un parmi vous s''est égaré loin de la vérité, et qu''un autre l''y ramène,'),
  (59, 5, 20, 'qu''il sache que celui qui ramènera un pécheur de la voie où il s''était égaré sauvera une âme de la mort et couvrira une multitude de péchés.'),
  (60, 1, 1, 'Pierre, apôtre de Jésus-Christ, à ceux qui sont étrangers et dispersés dans le Pont, la Galatie, la Cappadoce, l''Asie et la Bithynie,'),
  (60, 1, 2, 'et qui sont élus selon la prescience de Dieu le Père, par la sanctification de l''Esprit, afin qu''ils deviennent obéissants, et qu''ils participent à l''aspersion du sang de Jésus-Christ: que la grâce et la paix vous soient multipliées!'),
  (60, 1, 3, 'Béni soit Dieu, le Père de notre Seigneur Jésus-Christ, qui, selon sa grande miséricorde, nous a régénérés, pour une espérance vivante, par la résurrection de Jésus-Christ d''entre les morts,'),
  (60, 1, 4, 'pour un héritage qui ne se peut ni corrompre, ni souiller, ni flétrir, lequel vous est réservé dans les cieux,'),
  (60, 1, 5, 'à vous qui, par la puissance de Dieu, êtes gardés par la foi pour le salut prêt à être révélé dans les derniers temps!'),
  (60, 1, 6, 'C''est là ce qui fait votre joie, quoique maintenant, puisqu''il le faut, vous soyez attristés pour un peu de temps par diverses épreuves,'),
  (60, 1, 7, 'afin que l''épreuve de votre foi, plus précieuse que l''or périssable (qui cependant est éprouvé par le feu), ait pour résultat la louange, la gloire et l''honneur, lorsque Jésus-Christ apparaîtra,'),
  (60, 1, 8, 'lui que vous aimez sans l''avoir vu, en qui vous croyez sans le voir encore, vous réjouissant d''une joie ineffable et glorieuse,'),
  (60, 1, 9, 'parce que vous obtiendrez le salut de vos âmes pour prix de votre foi.'),
  (60, 1, 10, 'Les prophètes, qui ont prophétisé touchant la grâce qui vous était réservée, ont fait de ce salut l''objet de leurs recherches et de leurs investigations,'),
  (60, 1, 11, 'voulant sonder l''époque et les circonstances marquées par l''Esprit de Christ qui était en eux, et qui attestait d''avance les souffrances de Christ et la gloire dont elles seraient suivies.'),
  (60, 1, 12, 'Il leur fut révélé que ce n''était pas pour eux-mêmes, mais pour vous, qu''ils étaient les dispensateurs de ces choses, que vous ont annoncées maintenant ceux qui vous ont prêché l''Évangile par le Saint-Esprit envoyé du ciel, et dans lesquelles les anges désirent plonger leurs regards.'),
  (60, 1, 13, 'C''est pourquoi, ceignez les reins de votre entendement, soyez sobres, et ayez une entière espérance dans la grâce qui vous sera apportée, lorsque Jésus-Christ apparaîtra.'),
  (60, 1, 14, 'Comme des enfants obéissants, ne vous conformez pas aux convoitises que vous aviez autrefois, quand vous étiez dans l''ignorance.'),
  (60, 1, 15, 'Mais, puisque celui qui vous a appelés est saint, vous aussi soyez saints dans toute votre conduite,'),
  (60, 1, 16, 'selon qu''il est écrit: Vous serez saints, car je suis saint.'),
  (60, 1, 17, 'Et si vous invoquez comme Père celui qui juge selon l''œuvre de chacun, sans acception de personnes, conduisez-vous avec crainte pendant le temps de votre pèlerinage,'),
  (60, 1, 18, 'sachant que ce n''est pas par des choses périssables, par de l''argent ou de l''or, que vous avez été rachetés de la vaine manière de vivre que vous aviez héritée de vos pères,'),
  (60, 1, 19, 'mais par le sang précieux de Christ, comme d''un agneau sans défaut et sans tache,'),
  (60, 1, 20, 'prédestiné avant la fondation du monde, et manifesté à la fin des temps, à cause de vous,'),
  (60, 1, 21, 'qui par lui croyez en Dieu, lequel l''a ressuscité des morts et lui a donné la gloire, en sorte que votre foi et votre espérance reposent sur Dieu.'),
  (60, 1, 22, 'Ayant purifié vos âmes en obéissant à la vérité pour avoir un amour fraternel sincère, aimez-vous ardemment les uns les autres, de tout votre cœur,'),
  (60, 1, 23, 'puisque vous avez été régénérés, non par une semence corruptible, mais par une semence incorruptible, par la parole vivante et permanente de Dieu.'),
  (60, 1, 24, 'Car Toute chair est comme l''herbe, Et toute sa gloire comme la fleur de l''herbe. L''herbe sèche, et la fleur tombe;'),
  (60, 1, 25, 'Mais la parole du Seigneur demeure éternellement. Et cette parole est celle qui vous a été annoncée par l''Évangile.'),
  (60, 2, 1, 'Rejetant donc toute malice et toute ruse, la dissimulation, l''envie, et toute médisance,'),
  (60, 2, 2, 'désirez, comme des enfants nouveau-nés, le lait spirituel et pur, afin que par lui vous croissiez pour le salut,'),
  (60, 2, 3, 'si vous avez goûté que le Seigneur est bon.'),
  (60, 2, 4, 'Approchez-vous de lui, pierre vivante, rejetée par les hommes, mais choisie et précieuse devant Dieu;'),
  (60, 2, 5, 'et vous-mêmes, comme des pierres vivantes, édifiez-vous pour former une maison spirituelle, un saint sacerdoce, afin d''offrir des victimes spirituelles, agréables à Dieu par Jésus-Christ.'),
  (60, 2, 6, 'Car il est dit dans l''Écriture: Voici, je mets en Sion une pierre angulaire, choisie, précieuse; Et celui qui croit en elle ne sera point confus.'),
  (60, 2, 7, 'L''honneur est donc pour vous, qui croyez. Mais, pour les incrédules, La pierre qu''ont rejetée ceux qui bâtissaient Est devenue la principale de l''angle,'),
  (60, 2, 8, 'Et une pierre d''achoppement Et un rocher de scandale; ils s''y heurtent pour n''avoir pas cru à la parole, et c''est à cela qu''ils sont destinés.'),
  (60, 2, 9, 'Vous, au contraire, vous êtes une race élue, un sacerdoce royal, une nation sainte, un peuple acquis, afin que vous annonciez les vertus de celui qui vous a appelés des ténèbres à son admirable lumière,'),
  (60, 2, 10, 'vous qui autrefois n''étiez pas un peuple, et qui maintenant êtes le peuple de Dieu, vous qui n''aviez pas obtenu miséricorde, et qui maintenant avez obtenu miséricorde.'),
  (60, 2, 11, 'Bien-aimés, je vous exhorte, comme étrangers et voyageurs sur la terre, à vous abstenir des convoitises charnelles qui font la guerre à l''âme.'),
  (60, 2, 12, 'Ayez au milieu des païens une bonne conduite, afin que, là même où ils vous calomnient comme si vous étiez des malfaiteurs, ils remarquent vos bonnes œuvres, et glorifient Dieu, au jour où il les visitera.'),
  (60, 2, 13, 'Soyez soumis, à cause du Seigneur, à toute autorité établie parmi les hommes, soit au roi comme souverain,'),
  (60, 2, 14, 'soit aux gouverneurs comme envoyés par lui pour punir les malfaiteurs et pour approuver les gens de bien.'),
  (60, 2, 15, 'Car c''est la volonté de Dieu qu''en pratiquant le bien vous réduisiez au silence les hommes ignorants et insensés,'),
  (60, 2, 16, 'étant libres, sans faire de la liberté un voile qui couvre la méchanceté, mais agissant comme des serviteurs de Dieu.'),
  (60, 2, 17, 'Honorez tout le monde; aimez les frères; craignez Dieu; honorez le roi.'),
  (60, 2, 18, 'Serviteurs, soyez soumis en toute crainte à vos maîtres, non seulement à ceux qui sont bons et doux, mais aussi à ceux qui sont d''un caractère difficile.'),
  (60, 2, 19, 'Car c''est une grâce que de supporter des afflictions par motif de conscience envers Dieu, quand on souffre injustement.'),
  (60, 2, 20, 'En effet, quelle gloire y a-t-il à supporter de mauvais traitements pour avoir commis des fautes? Mais si vous supportez la souffrance lorsque vous faites ce qui est bien, c''est une grâce devant Dieu.'),
  (60, 2, 21, 'Et c''est à cela que vous avez été appelés, parce que Christ aussi a souffert pour vous, vous laissant un exemple, afin que vous suiviez ses traces,'),
  (60, 2, 22, 'Lui qui n''a point commis de péché, Et dans la bouche duquel il ne s''est point trouvé de fraude;'),
  (60, 2, 23, 'lui qui, injurié, ne rendait point d''injures, maltraité, ne faisait point de menaces, mais s''en remettait à celui qui juge justement;'),
  (60, 2, 24, 'lui qui a porté lui-même nos péchés en son corps sur le bois, afin que morts aux péchés nous vivions pour la justice; lui par les meurtrissures duquel vous avez été guéris.'),
  (60, 2, 25, 'Car vous étiez comme des brebis errantes. Mais maintenant vous êtes retournés vers le pasteur et le gardien de vos âmes.'),
  (60, 3, 1, 'Femmes, soyez de même soumises à vos maris, afin que, si quelques-uns n''obéissent point à la parole, ils soient gagnés sans parole par la conduite de leurs femmes,'),
  (60, 3, 2, 'en voyant votre manière de vivre chaste et réservée.'),
  (60, 3, 3, 'Ayez, non cette parure extérieure qui consiste dans les cheveux tressés, les ornements d''or, ou les habits qu''on revêt,'),
  (60, 3, 4, 'mais la parure intérieure et cachée dans le cœur, la pureté incorruptible d''un esprit doux et paisible, qui est d''un grand prix devant Dieu.'),
  (60, 3, 5, 'Ainsi se paraient autrefois les saintes femmes qui espéraient en Dieu, soumises à leurs maris,'),
  (60, 3, 6, 'comme Sara, qui obéissait à Abraham et l''appelait son seigneur. C''est d''elle que vous êtes devenues les filles, en faisant ce qui est bien, sans vous laisser troubler par aucune crainte.'),
  (60, 3, 7, 'Maris, montrez à votre tour de la sagesse dans vos rapports avec vos femmes, comme avec un sexe plus faible; honorez-les, comme devant aussi hériter avec vous de la grâce de la vie. Qu''il en soit ainsi, afin que rien ne vienne faire obstacle à vos prières.'),
  (60, 3, 8, 'Enfin, soyez tous animés des mêmes pensées et des mêmes sentiments, pleins d''amour fraternel, de compassion, d''humilité.'),
  (60, 3, 9, 'Ne rendez point mal pour mal, ou injure pour injure; bénissez, au contraire, car c''est à cela que vous avez été appelés, afin d''hériter la bénédiction.'),
  (60, 3, 10, 'Si quelqu''un, en effet, veut aimer la vie Et voir des jours heureux, Qu''il préserve sa langue du mal Et ses lèvres des paroles trompeuses,'),
  (60, 3, 11, 'Qu''il s''éloigne du mal et fasse le bien, Qu''il recherche la paix et la poursuive;'),
  (60, 3, 12, 'Car les yeux du Seigneur sont sur les justes Et ses oreilles sont attentives à leur prière, Mais la face du Seigneur est contre ceux qui font le mal.'),
  (60, 3, 13, 'Et qui vous maltraitera, si vous êtes zélés pour le bien?'),
  (60, 3, 14, 'D''ailleurs, quand vous souffririez pour la justice, vous seriez heureux. N''ayez d''eux aucune crainte, et ne soyez pas troublés;'),
  (60, 3, 15, 'Mais sanctifiez dans vos cœurs Christ le Seigneur, étant toujours prêts à vous défendre, avec douceur et respect, devant quiconque vous demande raison de l''espérance qui est en vous,'),
  (60, 3, 16, 'et ayant une bonne conscience, afin que, là même où ils vous calomnient comme si vous étiez des malfaiteurs, ceux qui décrient votre bonne conduite en Christ soient couverts de confusion.'),
  (60, 3, 17, 'Car il vaut mieux souffrir, si telle est la volonté de Dieu, en faisant le bien qu''en faisant le mal.'),
  (60, 3, 18, 'Christ aussi a souffert une fois pour les péchés, lui juste pour des injustes, afin de nous amener à Dieu, ayant été mis à mort quant à la chair, mais ayant été rendu vivant quant à l''Esprit,'),
  (60, 3, 19, 'dans lequel aussi il est allé prêcher aux esprits en prison,'),
  (60, 3, 20, 'qui autrefois avaient été incrédules, lorsque la patience de Dieu se prolongeait, aux jours de Noé, pendant la construction de l''arche, dans laquelle un petit nombre de personnes, c''est-à-dire huit, furent sauvées à travers l''eau.'),
  (60, 3, 21, 'Cette eau était une figure du baptême, qui n''est pas la purification des souillures du corps, mais l''engagement d''une bonne conscience envers Dieu, et qui maintenant vous sauve, vous aussi, par la résurrection de Jésus-Christ,'),
  (60, 3, 22, 'qui est à la droite de Dieu, depuis qu''il est allé au ciel, et que les anges, les autorités et les puissances, lui ont été soumis.'),
  (60, 4, 1, 'Ainsi donc, Christ ayant souffert dans la chair, vous aussi armez-vous de la même pensée. Car celui qui a souffert dans la chair en a fini avec le péché,'),
  (60, 4, 2, 'afin de vivre, non plus selon les convoitises des hommes, mais selon la volonté de Dieu, pendant le temps qui lui reste à vivre dans la chair.'),
  (60, 4, 3, 'C''est assez, en effet, d''avoir dans le temps passé accompli la volonté des païens, en marchant dans la dissolution, les convoitises, l''ivrognerie, les excès du manger et du boire, et les idolâtries criminelles.'),
  (60, 4, 4, 'Aussi trouvent-ils étrange que vous ne vous précipitiez pas avec eux dans le même débordement de débauche, et ils vous calomnient.'),
  (60, 4, 5, 'Ils rendront compte à celui qui est prêt à juger les vivants et les morts.'),
  (60, 4, 6, 'Car l''Évangile a été aussi annoncé aux morts, afin que, après avoir été jugés comme les hommes quant à la chair, ils vivent selon Dieu quant à l''Esprit.'),
  (60, 4, 7, 'La fin de toutes choses est proche. Soyez donc sages et sobres, pour vaquer à la prière.'),
  (60, 4, 8, 'Avant tout, ayez les uns pour les autres une ardente charité, car La charité couvre une multitude de péchés.'),
  (60, 4, 9, 'Exercez l''hospitalité les uns envers les autres, sans murmures.'),
  (60, 4, 10, 'Comme de bons dispensateurs des diverses grâces de Dieu, que chacun de vous mette au service des autres le don qu''il a reçu,'),
  (60, 4, 11, 'Si quelqu''un parle, que ce soit comme annonçant les oracles de Dieu; si quelqu''un remplit un ministère, qu''il le remplisse selon la force que Dieu communique, afin qu''en toutes choses Dieu soit glorifié par Jésus-Christ, à qui appartiennent la gloire et la puissance, aux siècles des siècles. Amen!'),
  (60, 4, 12, 'Bien-aimés, ne soyez pas surpris, comme d''une chose étrange qui vous arrive, de la fournaise qui est au milieu de vous pour vous éprouver.'),
  (60, 4, 13, 'Réjouissez-vous, au contraire, de la part que vous avez aux souffrances de Christ, afin que vous soyez aussi dans la joie et dans l''allégresse lorsque sa gloire apparaîtra.'),
  (60, 4, 14, 'Si vous êtes outragés pour le nom de Christ, vous êtes heureux, parce que l''Esprit de gloire, l''Esprit de Dieu, repose sur vous.'),
  (60, 4, 15, 'Que nul de vous, en effet, ne souffre comme meurtrier, ou voleur, ou malfaiteur, ou comme s''ingérant dans les affaires d''autrui.'),
  (60, 4, 16, 'Mais si quelqu''un souffre comme chrétien, qu''il n''en ait point honte, et que plutôt il glorifie Dieu à cause de ce nom.'),
  (60, 4, 17, 'Car c''est le moment où le jugement va commencer par la maison de Dieu. Or, si c''est par nous qu''il commence, quelle sera la fin de ceux qui n''obéissent pas à l''Évangile de Dieu?'),
  (60, 4, 18, 'Et si le juste se sauve avec peine, que deviendront l''impie et le pécheur?'),
  (60, 4, 19, 'Ainsi, que ceux qui souffrent selon la volonté de Dieu remettent leurs âmes au fidèle Créateur, en faisant ce qui est bien.'),
  (60, 5, 1, 'Voici les exhortations que j''adresse aux anciens qui sont parmi vous, moi ancien comme eux, témoin des souffrances de Christ, et participant de la gloire qui doit être manifestée:'),
  (60, 5, 2, 'Paissez le troupeau de Dieu qui est sous votre garde, non par contrainte, mais volontairement, selon Dieu; non pour un gain sordide, mais avec dévouement;'),
  (60, 5, 3, 'non comme dominant sur ceux qui vous sont échus en partage, mais en étant les modèles du troupeau.'),
  (60, 5, 4, 'Et lorsque le souverain pasteur paraîtra, vous obtiendrez la couronne incorruptible de la gloire.'),
  (60, 5, 5, 'De même, vous qui êtes jeunes, soyez soumis aux anciens. Et tous, dans vos rapports mutuels, revêtez-vous d''humilité; car Dieu résiste aux orgueilleux, Mais il fait grâce aux humbles.'),
  (60, 5, 6, 'Humiliez-vous donc sous la puissante main de Dieu, afin qu''il vous élève au temps convenable;'),
  (60, 5, 7, 'et déchargez-vous sur lui de tous vos soucis, car lui-même prend soin de vous.'),
  (60, 5, 8, 'Soyez sobres, veillez. Votre adversaire, le diable, rôde comme un lion rugissant, cherchant qui il dévorera.'),
  (60, 5, 9, 'Résistez-lui avec une foi ferme, sachant que les mêmes souffrances sont imposées à vos frères dans le monde.'),
  (60, 5, 10, 'Le Dieu de toute grâce, qui vous a appelés en Jésus-Christ à sa gloire éternelle, après que vous aurez souffert un peu de temps, vous perfectionnera lui-même, vous affermira, vous fortifiera, vous rendra inébranlables.'),
  (60, 5, 11, 'A lui soit la puissance aux siècles des siècles! Amen!'),
  (60, 5, 12, 'C''est par Silvain, qui est à mes yeux un frère fidèle, que je vous écris ce peu de mots, pour vous exhorter et pour vous attester que la grâce de Dieu à laquelle vous êtes attachés est la véritable.'),
  (60, 5, 13, 'L''Église des élus qui est à Babylone vous salue, ainsi que Marc, mon fils.'),
  (60, 5, 14, 'Saluez-vous les uns les autres par un baiser d''affection. Que la paix soit avec vous tous qui êtes en Christ!'),
  (61, 1, 1, 'Simon Pierre, serviteur et apôtre de Jésus-Christ, à ceux qui ont reçu en partage une foi du même prix que la nôtre, par la justice de notre Dieu et du Sauveur Jésus-Christ:'),
  (61, 1, 2, 'que la grâce et la paix vous soient multipliées par la connaissance de Dieu et de Jésus notre Seigneur!'),
  (61, 1, 3, 'Comme sa divine puissance nous a donné tout ce qui contribue à la vie et à la piété, au moyen de la connaissance de celui qui nous a appelés par sa propre gloire et par sa vertu,'),
  (61, 1, 4, 'lesquelles nous assurent de sa part les plus grandes et les plus précieuses promesses, afin que par elles vous deveniez participants de la nature divine, en fuyant la corruption qui existe dans le monde par la convoitise,'),
  (61, 1, 5, 'à cause de cela même, faites tous vos efforts pour joindre à votre foi la vertu, à la vertu la science,'),
  (61, 1, 6, 'à la science la tempérance, à la tempérance la patience, à la patience la piété,'),
  (61, 1, 7, 'à la piété l''amour fraternel, à l''amour fraternel la charité.'),
  (61, 1, 8, 'Car si ces choses sont en vous, et y sont avec abondance, elles ne vous laisseront point oisifs ni stériles pour la connaissance de notre Seigneur Jésus-Christ.'),
  (61, 1, 9, 'Mais celui en qui ces choses ne sont point est aveugle, il ne voit pas de loin, et il a mis en oubli la purification de ses anciens péchés.'),
  (61, 1, 10, 'C''est pourquoi, frères, appliquez-vous d''autant plus à affermir votre vocation et votre élection; car, en faisant cela, vous ne broncherez jamais.'),
  (61, 1, 11, 'C''est ainsi, en effet, que l''entrée dans le royaume éternel de notre Seigneur et Sauveur Jésus-Christ vous sera pleinement accordée.'),
  (61, 1, 12, 'Voilà pourquoi je prendrai soin de vous rappeler ces choses, bien que vous les sachiez et que vous soyez affermis dans la vérité présente.'),
  (61, 1, 13, 'Et je regarde comme un devoir, aussi longtemps que je suis dans cette tente, de vous tenir en éveil par des avertissements,'),
  (61, 1, 14, 'car je sais que je la quitterai subitement, ainsi que notre Seigneur Jésus-Christ me l''a fait connaître.'),
  (61, 1, 15, 'Mais j''aurai soin qu''après mon départ vous puissiez toujours vous souvenir de ces choses.'),
  (61, 1, 16, 'Ce n''est pas, en effet, en suivant des fables habilement conçues, que nous vous avons fait connaître la puissance et l''avènement de notre Seigneur Jésus-Christ, mais c''est comme ayant vu sa majesté de nos propres yeux.'),
  (61, 1, 17, 'Car il a reçu de Dieu le Père honneur et gloire, quand la gloire magnifique lui fit entendre une voix qui disait: Celui-ci est mon Fils bien-aimé, en qui j''ai mis toute mon affection.'),
  (61, 1, 18, 'Et nous avons entendu cette voix venant du ciel, lorsque nous étions avec lui sur la sainte montagne.'),
  (61, 1, 19, 'Et nous tenons pour d''autant plus certaine la parole prophétique, à laquelle vous faites bien de prêter attention, comme à une lampe qui brille dans un lieu obscur, jusqu''à ce que le jour vienne à paraître et que l''étoile du matin se lève dans vos cœurs;'),
  (61, 1, 20, 'sachant tout d''abord vous-mêmes qu''aucune prophétie de l''Écriture ne peut être un objet d''interprétation particulière,'),
  (61, 1, 21, 'car ce n''est pas par une volonté d''homme qu''une prophétie a jamais été apportée, mais c''est poussés par le Saint-Esprit que des hommes ont parlé de la part de Dieu.'),
  (61, 2, 1, 'Il y a eu parmi le peuple de faux prophètes, et il y aura de même parmi vous de faux docteurs, qui introduiront des sectes pernicieuses, et qui, reniant le maître qui les a rachetés, attireront sur eux une ruine soudaine.'),
  (61, 2, 2, 'Plusieurs les suivront dans leurs dissolutions, et la voie de la vérité sera calomniée à cause d''eux.'),
  (61, 2, 3, 'Par cupidité, ils trafiqueront de vous au moyen de paroles trompeuses, eux que menace depuis longtemps la condamnation, et dont la ruine ne sommeille point.'),
  (61, 2, 4, 'Car, si Dieu n''a pas épargné les anges qui ont péché, mais s''il les a précipités dans les abîmes de ténèbres et les réserve pour le jugement;'),
  (61, 2, 5, 's''il n''a pas épargné l''ancien monde, mais s''il a sauvé Noé, lui huitième, ce prédicateur de la justice, lorsqu''il fit venir le déluge sur un monde d''impies;'),
  (61, 2, 6, 's''il a condamné à la destruction et réduit en cendres les villes de Sodome et de Gomorrhe, les donnant comme exemple aux impies à venir,'),
  (61, 2, 7, 'et s''il a délivré le juste Lot, profondément attristé de la conduite de ces hommes sans frein dans leur dissolution'),
  (61, 2, 8, '(car ce juste, qui habitait au milieu d''eux, tourmentait journellement son âme juste à cause de ce qu''il voyait et entendait de leurs œuvres criminelles);'),
  (61, 2, 9, 'le Seigneur sait délivrer de l''épreuve les hommes pieux, et réserver les injustes pour être punis au jour du jugement,'),
  (61, 2, 10, 'ceux surtout qui vont après la chair dans un désir d''impureté et qui méprisent l''autorité. Audacieux et arrogants, ils ne craignent pas d''injurier les gloires,'),
  (61, 2, 11, 'tandis que les anges, supérieurs en force et en puissance, ne portent pas contre elles de jugement injurieux devant le Seigneur.'),
  (61, 2, 12, 'Mais eux, semblables à des brutes qui s''abandonnent à leurs penchants naturels et qui sont nées pour être prises et détruites, ils parlent d''une manière injurieuse de ce qu''ils ignorent, et ils périront par leur propre corruption,'),
  (61, 2, 13, 'recevant ainsi le salaire de leur iniquité. Ils trouvent leurs délices à se livrer au plaisir en plein jour; hommes tarés et souillés, ils se délectent dans leurs tromperies, en faisant bonne chère avec vous.'),
  (61, 2, 14, 'Ils ont les yeux pleins d''adultère et insatiables de péché; ils amorcent les âmes mal affermies; ils ont le cœur exercé à la cupidité; ce sont des enfants de malédiction.'),
  (61, 2, 15, 'Après avoir quitté le droit chemin, ils se sont égarés en suivant la voie de Balaam, fils de Bosor, qui aima le salaire de l''iniquité,'),
  (61, 2, 16, 'mais qui fut repris pour sa transgression: une ânesse muette, faisant entendre une voix d''homme, arrêta la démence du prophète.'),
  (61, 2, 17, 'Ces gens-là sont des fontaines sans eau, des nuées que chasse un tourbillon: l''obscurité des ténèbres leur est réservée.'),
  (61, 2, 18, 'Avec des discours enflés de vanité, ils amorcent par les convoitises de la chair, par les dissolutions, ceux qui viennent à peine d''échapper aux hommes qui vivent dans l''égarement;'),
  (61, 2, 19, 'ils leur promettent la liberté, quand ils sont eux-mêmes esclaves de la corruption, car chacun est esclave de ce qui a triomphé de lui.'),
  (61, 2, 20, 'En effet, si, après s''être retirés des souillures du monde, par la connaissance du Seigneur et Sauveur Jésus-Christ, ils s''y engagent de nouveau et sont vaincus, leur dernière condition est pire que la première.'),
  (61, 2, 21, 'Car mieux valait pour eux n''avoir pas connu la voie de la justice, que de se détourner, après l''avoir connue, du saint commandement qui leur avait été donné.'),
  (61, 2, 22, 'Il leur est arrivé ce que dit un proverbe vrai: Le chien est retourné à ce qu''il avait vomi, et la truie lavée s''est vautrée dans le bourbier.'),
  (61, 3, 1, 'Voici déjà, bien-aimés, la seconde lettre que je vous écris. Dans l''une et dans l''autre je cherche à éveiller par des avertissements votre saine intelligence,'),
  (61, 3, 2, 'afin que vous vous souveniez des choses annoncées d''avance par les saints prophètes, et du commandement du Seigneur et Sauveur, enseigné par vos apôtres,'),
  (61, 3, 3, 'sachant avant tout que, dans les derniers jours, il viendra des moqueurs avec leurs railleries, marchant selon leurs propres convoitises,'),
  (61, 3, 4, 'et disant: Où est la promesse de son avènement? Car, depuis que les pères sont morts, tout demeure comme dès le commencement de la création.'),
  (61, 3, 5, 'Ils veulent ignorer, en effet, que des cieux existèrent autrefois par la parole de Dieu, de même qu''une terre tirée de l''eau et formée au moyen de l''eau,'),
  (61, 3, 6, 'et que par ces choses le monde d''alors périt, submergé par l''eau,'),
  (61, 3, 7, 'tandis que, par la même parole, les cieux et la terre d''à présent sont gardés et réservés pour le feu, pour le jour du jugement et de la ruine des hommes impies.'),
  (61, 3, 8, 'Mais il est une chose, bien-aimés, que vous ne devez pas ignorer, c''est que, devant le Seigneur, un jour est comme mille ans, et mille ans sont comme un jour.'),
  (61, 3, 9, 'Le Seigneur ne tarde pas dans l''accomplissement de la promesse, comme quelques-uns le croient; mais il use de patience envers vous, ne voulant pas qu''aucun périsse, mais voulant que tous arrivent à la repentance.'),
  (61, 3, 10, 'Le jour du Seigneur viendra comme un voleur; en ce jour, les cieux passeront avec fracas, les éléments embrasés se dissoudront, et la terre avec les œuvres qu''elle renferme sera consumée.'),
  (61, 3, 11, 'Puisque donc toutes ces choses doivent se dissoudre, quelles ne doivent pas être la sainteté de votre conduite et votre piété,'),
  (61, 3, 12, 'tandis que vous attendez et hâtez l''avènement du jour de Dieu, à cause duquel les cieux enflammés se dissoudront et les éléments embrasés se fondront!'),
  (61, 3, 13, 'Mais nous attendons, selon sa promesse, de nouveaux cieux et une nouvelle terre, où la justice habitera.'),
  (61, 3, 14, 'C''est pourquoi, bien-aimés, en attendant ces choses, appliquez-vous à être trouvés par lui sans tache et irrépréhensibles dans la paix.'),
  (61, 3, 15, 'Croyez que la patience de notre Seigneur est votre salut, comme notre bien-aimé frère Paul vous l''a aussi écrit, selon la sagesse qui lui a été donnée.'),
  (61, 3, 16, 'C''est ce qu''il fait dans toutes les lettres, où il parle de ces choses, dans lesquelles il y a des points difficiles à comprendre, dont les personnes ignorantes et mal affermies tordent le sens, comme celui des autres Écritures, pour leur propre ruine.'),
  (61, 3, 17, 'Vous donc, bien-aimés, qui êtes avertis, mettez-vous sur vos gardes, de peur qu''entraînés par l''égarement des impies, vous ne veniez à déchoir de votre fermeté.'),
  (61, 3, 18, 'Mais croissez dans la grâce et dans la connaissance de notre Seigneur et Sauveur Jésus-Christ. A lui soit la gloire, maintenant et pour l''éternité! Amen!'),
  (62, 1, 1, 'Ce qui était dès le commencement, ce que nous avons entendu, ce que nous avons vu de nos yeux, ce que nous avons contemplé et que nos mains ont touché, concernant la parole de vie, -'),
  (62, 1, 2, 'car la vie a été manifestée, et nous l''avons vue et nous lui rendons témoignage, et nous vous annonçons la vie éternelle, qui était auprès du Père et qui nous a été manifestée, -'),
  (62, 1, 3, 'ce que nous avons vu et entendu, nous vous l''annonçons, à vous aussi, afin que vous aussi vous soyez en communion avec nous. Or, notre communion est avec le Père et avec son Fils Jésus-Christ.'),
  (62, 1, 4, 'Et nous écrivons ces choses, afin que notre joie soit parfaite.'),
  (62, 1, 5, 'La nouvelle que nous avons apprise de lui, et que nous vous annonçons, c''est que Dieu est lumière, et qu''il n''y a point en lui de ténèbres.'),
  (62, 1, 6, 'Si nous disons que nous sommes en communion avec lui, et que nous marchions dans les ténèbres, nous mentons, et nous ne pratiquons pas la vérité.'),
  (62, 1, 7, 'Mais si nous marchons dans la lumière, comme il est lui-même dans la lumière, nous sommes mutuellement en communion, et le sang de Jésus son Fils nous purifie de tout péché.'),
  (62, 1, 8, 'Si nous disons que nous n''avons pas de péché, nous nous séduisons nous-mêmes, et la vérité n''est point en nous.'),
  (62, 1, 9, 'Si nous confessons nos péchés, il est fidèle et juste pour nous les pardonner, et pour nous purifier de toute iniquité.'),
  (62, 1, 10, 'Si nous disons que nous n''avons pas péché, nous le faisons menteur, et sa parole n''est point en nous.'),
  (62, 2, 1, 'Mes petits enfants, je vous écris ces choses, afin que vous ne péchiez point. Et si quelqu''un a péché, nous avons un avocat auprès du Père, Jésus-Christ le juste.'),
  (62, 2, 2, 'Il est lui-même une victime expiatoire pour nos péchés, non seulement pour les nôtres, mais aussi pour ceux du monde entier.'),
  (62, 2, 3, 'Si nous gardons ses commandements, par là nous savons que nous l''avons connu.'),
  (62, 2, 4, 'Celui qui dit: Je l''ai connu, et qui ne garde pas ses commandements, est un menteur, et la vérité n''est point en lui.'),
  (62, 2, 5, 'Mais celui qui garde sa parole, l''amour de Dieu est véritablement parfait en lui: par là nous savons que nous sommes en lui.'),
  (62, 2, 6, 'Celui qui dit qu''il demeure en lui doit marcher aussi comme il a marché lui-même.'),
  (62, 2, 7, 'Bien-aimés, ce n''est pas un commandement nouveau que je vous écris, mais un commandement ancien que vous avez eu dès le commencement; ce commandement ancien, c''est la parole que vous avez entendue.'),
  (62, 2, 8, 'Toutefois, c''est un commandement nouveau que je vous écris, ce qui est vrai en lui et en vous, car les ténèbres se dissipent et la lumière véritable paraît déjà.'),
  (62, 2, 9, 'Celui qui dit qu''il est dans la lumière, et qui hait son frère, est encore dans les ténèbres.'),
  (62, 2, 10, 'Celui qui aime son frère demeure dans la lumière, et aucune occasion de chute n''est en lui.'),
  (62, 2, 11, 'Mais celui qui hait son frère est dans les ténèbres, il marche dans les ténèbres, et il ne sait où il va, parce que les ténèbres ont aveuglé ses yeux.'),
  (62, 2, 12, 'Je vous écris, petits enfants, parce que vos péchés vous sont pardonnés à cause de son nom.'),
  (62, 2, 13, 'Je vous écris, pères, parce que vous avez connu celui qui est dès le commencement. Je vous écris, jeunes gens, parce que vous avez vaincu le malin. Je vous ai écrit, petits enfants, parce que vous avez connu le Père.'),
  (62, 2, 14, 'Je vous ai écrit, pères, parce que vous avez connu celui qui est dès le commencement. Je vous ai écrit, jeunes gens, parce que vous êtes forts, et que la parole de Dieu demeure en vous, et que vous avez vaincu le malin.'),
  (62, 2, 15, 'N''aimez point le monde, ni les choses qui sont dans le monde. Si quelqu''un aime le monde, l''amour du Père n''est point en lui;'),
  (62, 2, 16, 'car tout ce qui est dans le monde, la convoitise de la chair, la convoitise des yeux, et l''orgueil de la vie, ne vient point du Père, mais vient du monde.'),
  (62, 2, 17, 'Et le monde passe, et sa convoitise aussi; mais celui qui fait la volonté de Dieu demeure éternellement.'),
  (62, 2, 18, 'Petits enfants, c''est la dernière heure, et comme vous avez appris qu''un antéchrist vient, il y a maintenant plusieurs antéchrists: par là nous connaissons que c''est la dernière heure.'),
  (62, 2, 19, 'Ils sont sortis du milieu de nous, mais ils n''étaient pas des nôtres; car s''ils eussent été des nôtres, ils seraient demeurés avec nous, mais cela est arrivé afin qu''il fût manifeste que tous ne sont pas des nôtres.'),
  (62, 2, 20, 'Pour vous, vous avez reçu l''onction de la part de celui qui est saint, et vous avez tous de la connaissance.'),
  (62, 2, 21, 'Je vous ai écrit, non que vous ne connaissiez pas la vérité, mais parce que vous la connaissez, et parce qu''aucun mensonge ne vient de la vérité.'),
  (62, 2, 22, 'Qui est menteur, sinon celui qui nie que Jésus est le Christ? Celui-là est l''antéchrist, qui nie le Père et le Fils.'),
  (62, 2, 23, 'Quiconque nie le Fils n''a pas non plus le Père; quiconque confesse le Fils a aussi le Père.'),
  (62, 2, 24, 'Que ce que vous avez entendu dès le commencement demeure en vous. Si ce que vous avez entendu dès le commencement demeure en vous, vous demeurerez aussi dans le Fils et dans le Père.'),
  (62, 2, 25, 'Et la promesse qu''il nous a faite, c''est la vie éternelle.'),
  (62, 2, 26, 'Je vous ai écrit ces choses au sujet de ceux qui vous égarent.'),
  (62, 2, 27, 'Pour vous, l''onction que vous avez reçue de lui demeure en vous, et vous n''avez pas besoin qu''on vous enseigne; mais comme son onction vous enseigne toutes choses, et qu''elle est véritable et qu''elle n''est point un mensonge, demeurez en lui selon les enseignements qu''elle vous a donnés.'),
  (62, 2, 28, 'Et maintenant, petits enfants, demeurez en lui, afin que, lorsqu''il paraîtra, nous ayons de l''assurance, et qu''à son avènement nous ne soyons pas confus et éloignés de lui.'),
  (62, 2, 29, 'Si vous savez qu''il est juste, reconnaissez que quiconque pratique la justice est né de lui.'),
  (62, 3, 1, 'Voyez quel amour le Père nous a témoigné, pour que nous soyons appelés enfants de Dieu! Et nous le sommes. Si le monde ne nous connaît pas, c''est qu''il ne l''a pas connu.'),
  (62, 3, 2, 'Bien-aimés, nous sommes maintenant enfants de Dieu, et ce que nous serons n''a pas encore été manifesté; mais nous savons que, lorsque cela sera manifesté, nous serons semblables à lui, parce que nous le verrons tel qu''il est.'),
  (62, 3, 3, 'Quiconque a cette espérance en lui se purifie, comme lui-même est pur.'),
  (62, 3, 4, 'Quiconque pèche transgresse la loi, et le péché est la transgression de la loi.'),
  (62, 3, 5, 'Or, vous le savez, Jésus a paru pour ôter les péchés, et il n''y a point en lui de péché.'),
  (62, 3, 6, 'Quiconque demeure en lui ne pèche point; quiconque pèche ne l''a pas vu, et ne l''a pas connu.'),
  (62, 3, 7, 'Petits enfants, que personne ne vous séduise. Celui qui pratique la justice est juste, comme lui-même est juste.'),
  (62, 3, 8, 'Celui qui pèche est du diable, car le diable pèche dès le commencement. Le Fils de Dieu a paru afin de détruire les œuvres du diable.'),
  (62, 3, 9, 'Quiconque est né de Dieu ne pratique pas le péché, parce que la semence de Dieu demeure en lui; et il ne peut pécher, parce qu''il est né de Dieu.'),
  (62, 3, 10, 'C''est par là que se font reconnaître les enfants de Dieu et les enfants du diable. Quiconque ne pratique pas la justice n''est pas de Dieu, non plus que celui qui n''aime pas son frère.'),
  (62, 3, 11, 'Car ce qui vous a été annoncé et ce que vous avez entendu dès le commencement, c''est que nous devons nous aimer les uns les autres,'),
  (62, 3, 12, 'et ne pas ressembler à Caïn, qui était du malin, et qui tua son frère. Et pourquoi le tua-t-il? parce que ses œuvres étaient mauvaises, et que celles de son frère étaient justes.'),
  (62, 3, 13, 'Ne vous étonnez pas, frères, si le monde vous hait.'),
  (62, 3, 14, 'Nous savons que nous sommes passés de la mort à la vie, parce que nous aimons les frères. Celui qui n''aime pas demeure dans la mort.'),
  (62, 3, 15, 'Quiconque hait son frère est un meurtrier, et vous savez qu''aucun meurtrier n''a la vie éternelle demeurant en lui.'),
  (62, 3, 16, 'Nous avons connu l''amour, en ce qu''il a donné sa vie pour nous; nous aussi, nous devons donner notre vie pour les frères.'),
  (62, 3, 17, 'Si quelqu''un possède les biens du monde, et que, voyant son frère dans le besoin, il lui ferme ses entrailles, comment l''amour de Dieu demeure-t-il en lui?'),
  (62, 3, 18, 'Petits enfants, n''aimons pas en paroles et avec la langue, mais en actions et avec vérité.'),
  (62, 3, 19, 'Par là nous connaîtrons que nous sommes de la vérité, et nous rassurerons nos cœurs devant lui;'),
  (62, 3, 20, 'car si notre cœur nous condamne, Dieu est plus grand que notre cœur, et il connaît toutes choses.'),
  (62, 3, 21, 'Bien-aimés, si notre cœur ne nous condamne pas, nous avons de l''assurance devant Dieu.'),
  (62, 3, 22, 'Quoi que ce soit que nous demandions, nous le recevons de lui, parce que nous gardons ses commandements et que nous faisons ce qui lui est agréable.'),
  (62, 3, 23, 'Et c''est ici son commandement: que nous croyions au nom de son Fils Jésus-Christ, et que nous nous aimions les uns les autres, selon le commandement qu''il nous a donné.'),
  (62, 3, 24, 'Celui qui garde ses commandements demeure en Dieu, et Dieu en lui; et nous connaissons qu''il demeure en nous par l''Esprit qu''il nous a donné.'),
  (62, 4, 1, 'Bien-aimés, n''ajoutez pas foi à tout esprit; mais éprouvez les esprits, pour savoir s''ils sont de Dieu, car plusieurs faux prophètes sont venus dans le monde.'),
  (62, 4, 2, 'Reconnaissez à ceci l''Esprit de Dieu: tout esprit qui confesse Jésus-Christ venu en chair est de Dieu;'),
  (62, 4, 3, 'et tout esprit qui ne confesse pas Jésus n''est pas de Dieu, c''est celui de l''antéchrist, dont vous avez appris la venue, et qui maintenant est déjà dans le monde.'),
  (62, 4, 4, 'Vous, petits enfants, vous êtes de Dieu, et vous les avez vaincus, parce que celui qui est en vous est plus grand que celui qui est dans le monde.'),
  (62, 4, 5, 'Eux, ils sont du monde; c''est pourquoi ils parlent d''après le monde, et le monde les écoute.'),
  (62, 4, 6, 'Nous, nous sommes de Dieu; celui qui connaît Dieu nous écoute; celui qui n''est pas de Dieu ne nous écoute pas: c''est par là que nous connaissons l''esprit de la vérité et l''esprit de l''erreur.'),
  (62, 4, 7, 'Bien-aimés, aimons nous les uns les autres; car l''amour est de Dieu, et quiconque aime est né de Dieu et connaît Dieu.'),
  (62, 4, 8, 'Celui qui n''aime pas n''a pas connu Dieu, car Dieu est amour.'),
  (62, 4, 9, 'L''amour de Dieu a été manifesté envers nous en ce que Dieu a envoyé son Fils unique dans le monde, afin que nous vivions par lui.'),
  (62, 4, 10, 'Et cet amour consiste, non point en ce que nous avons aimé Dieu, mais en ce qu''il nous a aimés et a envoyé son Fils comme victime expiatoire pour nos péchés.'),
  (62, 4, 11, 'Bien-aimés, si Dieu nous a ainsi aimés, nous devons aussi nous aimer les uns les autres.'),
  (62, 4, 12, 'Personne n''a jamais vu Dieu; si nous nous aimons les uns les autres, Dieu demeure en nous, et son amour est parfait en nous.'),
  (62, 4, 13, 'Nous connaissons que nous demeurons en lui, et qu''il demeure en nous, en ce qu''il nous a donné de son Esprit.'),
  (62, 4, 14, 'Et nous, nous avons vu et nous attestons que le Père a envoyé le Fils comme Sauveur du monde.'),
  (62, 4, 15, 'Celui qui confessera que Jésus est le Fils de Dieu, Dieu demeure en lui, et lui en Dieu.'),
  (62, 4, 16, 'Et nous, nous avons connu l''amour que Dieu a pour nous, et nous y avons cru. Dieu est amour; et celui qui demeure dans l''amour demeure en Dieu, et Dieu demeure en lui.'),
  (62, 4, 17, 'Tel il est, tels nous sommes aussi dans ce monde: c''est en cela que l''amour est parfait en nous, afin que nous ayons de l''assurance au jour du jugement.'),
  (62, 4, 18, 'La crainte n''est pas dans l''amour, mais l''amour parfait bannit la crainte; car la crainte suppose un châtiment, et celui qui craint n''est pas parfait dans l''amour.'),
  (62, 4, 19, 'Pour nous, nous l''aimons, parce qu''il nous a aimés le premier.'),
  (62, 4, 20, 'Si quelqu''un dit: J''aime Dieu, et qu''il haïsse son frère, c''est un menteur; car celui qui n''aime pas son frère qu''il voit, comment peut-il aimer Dieu qu''il ne voit pas?'),
  (62, 4, 21, 'Et nous avons de lui ce commandement: que celui qui aime Dieu aime aussi son frère.'),
  (62, 5, 1, 'Quiconque croit que Jésus est le Christ, est né de Dieu, et quiconque aime celui qui l''a engendré aime aussi celui qui est né de lui.'),
  (62, 5, 2, 'Nous connaissons que nous aimons les enfants de Dieu, lorsque nous aimons Dieu, et que nous pratiquons ses commandements.'),
  (62, 5, 3, 'Car l''amour de Dieu consiste à garder ses commandements. Et ses commandements ne sont pas pénibles,'),
  (62, 5, 4, 'parce que tout ce qui est né de Dieu triomphe du monde; et la victoire qui triomphe du monde, c''est notre foi.'),
  (62, 5, 5, 'Qui est celui qui a triomphé du monde, sinon celui qui croit que Jésus est le Fils de Dieu?'),
  (62, 5, 6, 'C''est lui, Jésus-Christ, qui est venu avec de l''eau et du sang; non avec l''eau seulement, mais avec l''eau et avec le sang; et c''est l''Esprit qui rend témoignage, parce que l''Esprit est la vérité.'),
  (62, 5, 7, 'Car il y en a trois qui rendent témoignage:'),
  (62, 5, 8, 'l''Esprit, l''eau et le sang, et les trois sont d''accord.'),
  (62, 5, 9, 'Si nous recevons le témoignage des hommes, le témoignage de Dieu est plus grand; car le témoignage de Dieu consiste en ce qu''il a rendu témoignage à son Fils.'),
  (62, 5, 10, 'Celui qui croit au Fils de Dieu a ce témoignage en lui-même; celui qui ne croit pas Dieu le fait menteur, puisqu''il ne croit pas au témoignage que Dieu a rendu à son Fils.'),
  (62, 5, 11, 'Et voici ce témoignage, c''est que Dieu nous a donné la vie éternelle, et que cette vie est dans son Fils.'),
  (62, 5, 12, 'Celui qui a le Fils a la vie; celui qui n''a pas le Fils de Dieu n''a pas la vie.'),
  (62, 5, 13, 'Je vous ai écrit ces choses, afin que vous sachiez que vous avez la vie éternelle, vous qui croyez au nom du Fils de Dieu.'),
  (62, 5, 14, 'Nous avons auprès de lui cette assurance, que si nous demandons quelque chose selon sa volonté, il nous écoute.'),
  (62, 5, 15, 'Et si nous savons qu''il nous écoute, quelque chose que nous demandions, nous savons que nous possédons la chose que nous lui avons demandée.'),
  (62, 5, 16, 'Si quelqu''un voit son frère commettre un péché qui ne mène point à la mort, qu''il prie, et Dieu donnera la vie à ce frère, il la donnera à ceux qui commettent un péché qui ne mène point à la mort. Il y a un péché qui mène à la mort; ce n''est pas pour ce péché-là que je dis de prier.'),
  (62, 5, 17, 'Toute iniquité est un péché, et il y a tel péché qui ne mène pas à la mort.'),
  (62, 5, 18, 'Nous savons que quiconque est né de Dieu ne pèche point; mais celui qui est né de Dieu se garde lui-même, et le malin ne le touche pas.'),
  (62, 5, 19, 'Nous savons que nous sommes de Dieu, et que le monde entier est sous la puissance du malin.'),
  (62, 5, 20, 'Nous savons aussi que le Fils de Dieu est venu, et qu''il nous a donné l''intelligence pour connaître le Véritable; et nous sommes dans le Véritable, en son Fils Jésus-Christ. C''est lui qui est le Dieu véritable, et la vie éternelle.'),
  (62, 5, 21, 'Petits enfants, gardez-vous des idoles.'),
  (63, 1, 1, 'L''ancien, à Kyria l''élue et à ses enfants, que j''aime dans la vérité, -et ce n''est pas moi seul qui les aime, mais aussi tous ceux qui ont connu la vérité, -'),
  (63, 1, 2, 'à cause de la vérité qui demeure en nous, et qui sera avec nous pour l''éternité:'),
  (63, 1, 3, 'que la grâce, la miséricorde et la paix soient avec vous de la part de Dieu le Père et de la part de Jésus-Christ, le Fils du Père, dans la vérité et la charité!'),
  (63, 1, 4, 'J''ai été fort réjoui de trouver de tes enfants qui marchent dans la vérité, selon le commandement que nous avons reçu du Père.'),
  (63, 1, 5, 'Et maintenant, ce que je te demande, Kyria, -non comme te prescrivant un commandement nouveau, mais celui que nous avons eu dès le commencement, -c''est que nous nous aimions les uns les autres.'),
  (63, 1, 6, 'Et l''amour consiste à marcher selon ses commandements. C''est là le commandement dans lequel vous devez marcher, comme vous l''avez appris dès le commencement.'),
  (63, 1, 7, 'Car plusieurs séducteurs sont entrés dans le monde, qui ne confessent point que Jésus-Christ est venu en chair. Celui qui est tel, c''est le séducteur et l''antéchrist.'),
  (63, 1, 8, 'Prenez garde à vous-mêmes, afin que vous ne perdiez pas le fruit de votre travail, mais que vous receviez une pleine récompense.'),
  (63, 1, 9, 'Quiconque va plus loin et ne demeure pas dans la doctrine de Christ n''a point Dieu; celui qui demeure dans cette doctrine a le Père et le Fils.'),
  (63, 1, 10, 'Si quelqu''un vient à vous et n''apporte pas cette doctrine, ne le recevez pas dans votre maison, et ne lui dites pas: Salut!'),
  (63, 1, 11, 'car celui qui lui dit: Salut! participe à ses mauvaises œuvres.'),
  (63, 1, 12, 'Quoique j''eusse beaucoup de choses à vous écrire, je n''ai pas voulu le faire avec le papier et l''encre; mais j''espère aller chez vous, et vous parler bouche à bouche, afin que notre joie soit parfaite.'),
  (63, 1, 13, 'Les enfants de ta sœur l''élue te saluent.'),
  (64, 1, 1, 'L''ancien, à Gaïus, le bien-aimé, que j''aime dans la vérité.'),
  (64, 1, 2, 'Bien-aimé, je souhaite que tu prospères à tous égards et sois en bonne santé, comme prospère l''état de ton âme.'),
  (64, 1, 3, 'J''ai été fort réjoui, lorsque des frères sont arrivés et ont rendu témoignage de la vérité qui est en toi, de la manière dont tu marches dans la vérité.'),
  (64, 1, 4, 'Je n''ai pas de plus grande joie que d''apprendre que mes enfants marchent dans la vérité.'),
  (64, 1, 5, 'Bien-aimé, tu agis fidèlement dans ce que tu fais pour les frères, et même pour des frères étrangers,'),
  (64, 1, 6, 'lesquels ont rendu témoignage de ta charité, en présence de l''Église. Tu feras bien de pourvoir à leur voyage d''une manière digne de Dieu.'),
  (64, 1, 7, 'Car c''est pour le nom de Jésus-Christ qu''ils sont partis, sans rien recevoir des païens.'),
  (64, 1, 8, 'Nous devons donc accueillir de tels hommes, afin d''être ouvriers avec eux pour la vérité.'),
  (64, 1, 9, 'J''ai écrit quelques mots à l''Église; mais Diotrèphe, qui aime à être le premier parmi eux, ne nous reçoit point.'),
  (64, 1, 10, 'C''est pourquoi, si je vais vous voir, je rappellerai les actes qu''il commet, en tenant contre nous de méchants propos; non content de cela, il ne reçoit pas les frères, et ceux qui voudraient le faire, il les en empêche et les chasse de l''Église.'),
  (64, 1, 11, 'Bien-aimé, n''imite pas le mal, mais le bien. Celui qui fait le bien est de Dieu; celui qui fait le mal n''a point vu Dieu.'),
  (64, 1, 12, 'Tous, et la vérité elle-même, rendent un bon témoignage à Démétrius; nous aussi, nous lui rendons témoignage, et tu sais que notre témoignage est vrai.'),
  (64, 1, 13, 'J''aurais beaucoup de choses à t''écrire, mais je ne veux pas le faire avec l''encre et la plume.'),
  (64, 1, 14, 'J''espère te voir bientôt, et nous parlerons de bouche à bouche. Que la paix soit avec toi! Les amis te saluent. Salue les amis, chacun en particulier.'),
  (65, 1, 1, 'Jude, serviteur de Jésus-Christ, et frère de Jacques, à ceux qui ont été appelés, qui sont aimés en Dieu le Père, et gardés pour Jésus-Christ:'),
  (65, 1, 2, 'que la miséricorde, la paix et la charité vous soient multipliées!'),
  (65, 1, 3, 'Bien-aimés, comme je désirais vivement vous écrire au sujet de notre salut commun, je me suis senti obligé de le faire afin de vous exhorter à combattre pour la foi qui a été transmise aux saints une fois pour toutes.'),
  (65, 1, 4, 'Car il s''est glissé parmi vous certains hommes, dont la condamnation est écrite depuis longtemps, des impies, qui changent la grâce de notre Dieu en dissolution, et qui renient notre seul maître et Seigneur Jésus-Christ.'),
  (65, 1, 5, 'Je veux vous rappeler, à vous qui savez fort bien toutes ces choses, que le Seigneur, après avoir sauvé le peuple et l''avoir tiré du pays d''Égypte, fit ensuite périr les incrédules;'),
  (65, 1, 6, 'qu''il a réservé pour le jugement du grand jour, enchaînés éternellement par les ténèbres, les anges qui n''ont pas gardé leur dignité, mais qui ont abandonné leur propre demeure;'),
  (65, 1, 7, 'que Sodome et Gomorrhe et les villes voisines, qui se livrèrent comme eux à l''impudicité et à des vices contre nature, sont données en exemple, subissant la peine d''un feu éternel.'),
  (65, 1, 8, 'Malgré cela, ces hommes aussi, entraînés par leurs rêveries, souillent pareillement leur chair, méprisent l''autorité et injurient les gloires.'),
  (65, 1, 9, 'Or, l''archange Michel, lorsqu''il contestait avec le diable et lui disputait le corps de Moïse, n''osa pas porter contre lui un jugement injurieux, mais il dit: Que le Seigneur te réprime!'),
  (65, 1, 10, 'Eux, au contraire, ils parlent d''une manière injurieuse de ce qu''ils ignorent, et ils se corrompent dans ce qu''ils savent naturellement comme les brutes.'),
  (65, 1, 11, 'Malheur à eux! car ils ont suivi la voie de Caïn, ils se sont jetés pour un salaire dans l''égarement de Balaam, ils se sont perdus par la révolte de Coré.'),
  (65, 1, 12, 'Ce sont des écueils dans vos agapes, faisant impudemment bonne chère, se repaissant eux-mêmes. Ce sont des nuées sans eau, poussées par les vents; des arbres d''automne sans fruits, deux fois morts, déracinés;'),
  (65, 1, 13, 'des vagues furieuses de la mer, rejetant l''écume de leurs impuretés; des astres errants, auxquels l''obscurité des ténèbres est réservée pour l''éternité.'),
  (65, 1, 14, 'C''est aussi pour eux qu''Énoch, le septième depuis Adam, a prophétisé en ces termes: Voici, le Seigneur est venu avec ses saintes myriades,'),
  (65, 1, 15, 'pour exercer un jugement contre tous, et pour faire rendre compte à tous les impies parmi eux de tous les actes d''impiété qu''ils ont commis et de toutes les paroles injurieuses qu''ont proférées contre lui des pécheurs impies.'),
  (65, 1, 16, 'Ce sont des gens qui murmurent, qui se plaignent de leur sort, qui marchent selon leurs convoitises, qui ont à la bouche des paroles hautaines, qui admirent les personnes par motif d''intérêt.'),
  (65, 1, 17, 'Mais vous, bien-aimés, souvenez-vous des choses annoncées d''avance par les apôtres de notre Seigneur Jésus-Christ.'),
  (65, 1, 18, 'Ils vous disaient qu''au dernier temps il y aurait des moqueurs, marchant selon leurs convoitises impies;'),
  (65, 1, 19, 'ce sont ceux qui provoquent des divisions, hommes sensuels, n''ayant pas l''esprit.'),
  (65, 1, 20, 'Pour vous, bien-aimés, vous édifiant vous-mêmes sur votre très sainte foi, et priant par le Saint-Esprit,'),
  (65, 1, 21, 'maintenez-vous dans l''amour de Dieu, en attendant la miséricorde de notre Seigneur Jésus-Christ pour la vie éternelle.'),
  (65, 1, 22, 'Reprenez les uns, ceux qui contestent;'),
  (65, 1, 23, 'sauvez-en d''autres en les arrachant du feu; et pour d''autres encore, ayez une pitié mêlée de crainte, haïssant jusqu''à la tunique souillée par la chair.'),
  (65, 1, 24, 'Or, à celui qui peut vous préserver de toute chute et vous faire paraître devant sa gloire irrépréhensibles et dans l''allégresse,'),
  (65, 1, 25, 'à Dieu seul, notre Sauveur, par Jésus-Christ notre Seigneur, soient gloire, majesté, force et puissance, dès avant tous les temps, et maintenant, et dans tous les siècles! Amen!'),
  (66, 1, 1, 'Révélation de Jésus-Christ, que Dieu lui a donnée pour montrer à ses serviteurs les choses qui doivent arriver bientôt, et qu''il a fait connaître, par l''envoi de son ange, à son serviteur Jean,'),
  (66, 1, 2, 'lequel a attesté la parole de Dieu et le témoignage de Jésus-Christ, tout ce qu''il a vu.'),
  (66, 1, 3, 'Heureux celui qui lit et ceux qui entendent les paroles de la prophétie, et qui gardent les choses qui y sont écrites! Car le temps est proche.'),
  (66, 1, 4, 'Jean aux sept Églises qui sont en Asie: que la grâce et la paix vous soient données de la part de celui qui est, qui était, et qui vient, et de la part des sept esprits qui sont devant son trône,'),
  (66, 1, 5, 'et de la part de Jésus-Christ, le témoin fidèle, le premier-né des morts, et le prince des rois de la terre! A celui qui nous aime, qui nous a délivrés de nos péchés par son sang,'),
  (66, 1, 6, 'et qui a fait de nous un royaume, des sacrificateurs pour Dieu son Père, à lui soient la gloire et la puissance, aux siècles des siècles! Amen!'),
  (66, 1, 7, 'Voici, il vient avec les nuées. Et tout œil le verra, même ceux qui l''ont percé; et toutes les tribus de la terre se lamenteront à cause de lui. Oui. Amen!'),
  (66, 1, 8, 'Je suis l''alpha et l''oméga, dit le Seigneur Dieu, celui qui est, qui était, et qui vient, le Tout-Puissant.'),
  (66, 1, 9, 'Moi Jean, votre frère, et qui ai part avec vous à la tribulation et au royaume et à la persévérance en Jésus, j''étais dans l''île appelée Patmos, à cause de la parole de Dieu et du témoignage de Jésus.'),
  (66, 1, 10, 'Je fus ravi en esprit au jour du Seigneur, et j''entendis derrière moi une voix forte, comme le son d''une trompette,'),
  (66, 1, 11, 'qui disait: Ce que tu vois, écris-le dans un livre, et envoie-le aux sept Églises, à Éphèse, à Smyrne, à Pergame, à Thyatire, à Sardes, à Philadelphie, et à Laodicée.'),
  (66, 1, 12, 'Je me retournai pour connaître quelle était la voix qui me parlait. Et, après m''être retourné, je vis sept chandeliers d''or,'),
  (66, 1, 13, 'et, au milieu des sept chandeliers, quelqu''un qui ressemblait à un fils d''homme, vêtu d''une longue robe, et ayant une ceinture d''or sur la poitrine.'),
  (66, 1, 14, 'Sa tête et ses cheveux étaient blancs comme de la laine blanche, comme de la neige; ses yeux étaient comme une flamme de feu;'),
  (66, 1, 15, 'ses pieds étaient semblables à de l''airain ardent, comme s''il eût été embrasé dans une fournaise; et sa voix était comme le bruit de grandes eaux.'),
  (66, 1, 16, 'Il avait dans sa main droite sept étoiles. De sa bouche sortait une épée aiguë, à deux tranchants; et son visage était comme le soleil lorsqu''il brille dans sa force.'),
  (66, 1, 17, 'Quand je le vis, je tombai à ses pieds comme mort. Il posa sur moi sa main droite en disant: Ne crains point! Je suis le premier et le dernier,'),
  (66, 1, 18, 'et le vivant. J''étais mort; et voici, je suis vivant aux siècles des siècles. Je tiens les clefs de la mort et du séjour des morts.'),
  (66, 1, 19, 'Écris donc les choses que tu as vues, et celles qui sont, et celles qui doivent arriver après elles,'),
  (66, 1, 20, 'le mystère des sept étoiles que tu as vues dans ma main droite, et des sept chandeliers d''or. Les sept étoiles sont les anges des sept Églises, et les sept chandeliers sont les sept Églises.'),
  (66, 2, 1, 'Écris à l''ange de l''Église d''Éphèse: Voici ce que dit celui qui tient les sept étoiles dans sa main droite, celui qui marche au milieu des sept chandeliers d''or:'),
  (66, 2, 2, 'Je connais tes œuvres, ton travail, et ta persévérance. Je sais que tu ne peux supporter les méchants; que tu as éprouvé ceux qui se disent apôtres et qui ne le sont pas, et que tu les as trouvés menteurs;'),
  (66, 2, 3, 'que tu as de la persévérance, que tu as souffert à cause de mon nom, et que tu ne t''es point lassé.'),
  (66, 2, 4, 'Mais ce que j''ai contre toi, c''est que tu as abandonné ton premier amour.'),
  (66, 2, 5, 'Souviens-toi donc d''où tu es tombé, repens-toi, et pratique tes premières œuvres; sinon, je viendrai à toi, et j''ôterai ton chandelier de sa place, à moins que tu ne te repentes.'),
  (66, 2, 6, 'Tu as pourtant ceci, c''est que tu hais les œuvres des Nicolaïtes, œuvres que je hais aussi.'),
  (66, 2, 7, 'Que celui qui a des oreilles entende ce que l''Esprit dit aux Églises: A celui qui vaincra je donnerai à manger de l''arbre de vie, qui est dans le paradis de Dieu.'),
  (66, 2, 8, 'Écris à l''ange de l''Église de Smyrne: Voici ce que dit le premier et le dernier, celui qui était mort, et qui est revenu à la vie:'),
  (66, 2, 9, 'Je connais ta tribulation et ta pauvreté (bien que tu sois riche), et les calomnies de la part de ceux qui se disent Juifs et ne le sont pas, mais qui sont une synagogue de Satan.'),
  (66, 2, 10, 'Ne crains pas ce que tu vas souffrir. Voici, le diable jettera quelques-uns de vous en prison, afin que vous soyez éprouvés, et vous aurez une tribulation de dix jours. Sois fidèle jusqu''à la mort, et je te donnerai la couronne de vie.'),
  (66, 2, 11, 'Que celui qui a des oreilles entende ce que l''Esprit dit aux Églises: Celui qui vaincra n''aura pas à souffrir la seconde mort.'),
  (66, 2, 12, 'Écris à l''ange de l''Église de Pergame: Voici ce que dit celui qui a l''épée aiguë, à deux tranchants:'),
  (66, 2, 13, 'Je sais où tu demeures, je sais que là est le trône de Satan. Tu retiens mon nom, et tu n''as pas renié ma foi, même aux jours d''Antipas, mon témoin fidèle, qui a été mis à mort chez vous, là où Satan a sa demeure.'),
  (66, 2, 14, 'Mais j''ai quelque chose contre toi, c''est que tu as là des gens attachés à la doctrine de Balaam, qui enseignait à Balak à mettre une pierre d''achoppement devant les fils d''Israël, pour qu''ils mangeassent des viandes sacrifiées aux idoles et qu''ils se livrassent à l''impudicité.'),
  (66, 2, 15, 'De même, toi aussi, tu as des gens attachés pareillement à la doctrine des Nicolaïtes.'),
  (66, 2, 16, 'Repens-toi donc; sinon, je viendrai à toi bientôt, et je les combattrai avec l''épée de ma bouche.'),
  (66, 2, 17, 'Que celui qui a des oreilles entende ce que l''Esprit dit aux Églises: A celui qui vaincra je donnerai de la manne cachée, et je lui donnerai un caillou blanc; et sur ce caillou est écrit un nom nouveau, que personne ne connaît, si ce n''est celui qui le reçoit.'),
  (66, 2, 18, 'Écris à l''ange de l''Église de Thyatire: Voici ce que dit le Fils de Dieu, celui qui a les yeux comme une flamme de feu, et dont les pieds sont semblables à de l''airain ardent:'),
  (66, 2, 19, 'Je connais tes œuvres, ton amour, ta foi, ton fidèle service, ta constance, et tes dernières œuvres plus nombreuses que les premières.'),
  (66, 2, 20, 'Mais ce que j''ai contre toi, c''est que tu laisses la femme Jézabel, qui se dit prophétesse, enseigner et séduire mes serviteurs, pour qu''ils se livrent à l''impudicité et qu''ils mangent des viandes sacrifiées aux idoles.'),
  (66, 2, 21, 'Je lui ai donné du temps, afin qu''elle se repentît, et elle ne veut pas se repentir de son impudicité.'),
  (66, 2, 22, 'Voici, je vais la jeter sur un lit, et envoyer une grande tribulation à ceux qui commettent adultère avec elle, à moins qu''ils ne se repentent de leurs œuvres.'),
  (66, 2, 23, 'Je ferai mourir de mort ses enfants; et toutes les Églises connaîtront que je suis celui qui sonde les reins et les cœurs, et je vous rendrai à chacun selon vos œuvres.'),
  (66, 2, 24, 'A vous, à tous les autres de Thyatire, qui ne reçoivent pas cette doctrine, et qui n''ont pas connu les profondeurs de Satan, comme ils les appellent, je vous dis: Je ne mets pas sur vous d''autre fardeau;'),
  (66, 2, 25, 'seulement, ce que vous avez, retenez-le jusqu''à ce que je vienne.'),
  (66, 2, 26, 'A celui qui vaincra, et qui gardera jusqu''à la fin mes œuvres, je donnerai autorité sur les nations.'),
  (66, 2, 27, 'Il les paîtra avec une verge de fer, comme on brise les vases d''argile, ainsi que moi-même j''en ai reçu le pouvoir de mon Père.'),
  (66, 2, 28, 'Et je lui donnerai l''étoile du matin.'),
  (66, 2, 29, 'Que celui qui a des oreilles entende ce que l''Esprit dit aux Églises!'),
  (66, 3, 1, 'Écris à l''ange de l''Église de Sardes: Voici ce que dit celui qui a les sept esprits de Dieu et les sept étoiles: Je connais tes œuvres. Je sais que tu passes pour être vivant, et tu es mort.'),
  (66, 3, 2, 'Sois vigilant, et affermis le reste qui est près de mourir; car je n''ai pas trouvé tes œuvres parfaites devant mon Dieu.'),
  (66, 3, 3, 'Rappelle-toi donc comment tu as reçu et entendu, et garde, et repens-toi. Si tu ne veilles pas, je viendrai comme un voleur, et tu ne sauras pas à quelle heure je viendrai sur toi.'),
  (66, 3, 4, 'Cependant tu as à Sardes quelques hommes qui n''ont pas souillé leurs vêtements; ils marcheront avec moi en vêtements blancs, parce qu''ils en sont dignes.'),
  (66, 3, 5, 'Celui qui vaincra sera revêtu ainsi de vêtements blancs; je n''effacerai point son nom du livre de vie, et je confesserai son nom devant mon Père et devant ses anges.'),
  (66, 3, 6, 'Que celui qui a des oreilles entende ce que l''Esprit dit aux Églises!'),
  (66, 3, 7, 'Écris à l''ange de l''Église de Philadelphie: Voici ce que dit le Saint, le Véritable, celui qui a la clef de David, celui qui ouvre, et personne ne fermera, celui qui ferme, et personne n''ouvrira:'),
  (66, 3, 8, 'Je connais tes œuvres. Voici, parce que tu as peu de puissance, et que tu as gardé ma parole, et que tu n''as pas renié mon nom, j''ai mis devant toi une porte ouverte, que personne ne peut fermer.'),
  (66, 3, 9, 'Voici, je te donne de ceux de la synagogue de Satan, qui se disent Juifs et ne le sont pas, mais qui mentent; voici, je les ferai venir, se prosterner à tes pieds, et connaître que je t''ai aimé.'),
  (66, 3, 10, 'Parce que tu as gardé la parole de la persévérance en moi, je te garderai aussi à l''heure de la tentation qui va venir sur le monde entier, pour éprouver les habitants de la terre.'),
  (66, 3, 11, 'Je viens bientôt. Retiens ce que tu as, afin que personne ne prenne ta couronne.'),
  (66, 3, 12, 'Celui qui vaincra, je ferai de lui une colonne dans le temple de mon Dieu, et il n''en sortira plus; j''écrirai sur lui le nom de mon Dieu, et le nom de la ville de mon Dieu, de la nouvelle Jérusalem qui descend du ciel d''auprès de mon Dieu, et mon nom nouveau.'),
  (66, 3, 13, 'Que celui qui a des oreilles entende ce que l''Esprit dit aux Églises!'),
  (66, 3, 14, 'Écris à l''ange de l''Église de Laodicée: Voici ce que dit l''Amen, le témoin fidèle et véritable, le commencement de la création de Dieu:'),
  (66, 3, 15, 'Je connais tes œuvres. Je sais que tu n''es ni froid ni bouillant. Puisses-tu être froid ou bouillant!'),
  (66, 3, 16, 'Ainsi, parce que tu es tiède, et que tu n''es ni froid ni bouillant, je te vomirai de ma bouche.'),
  (66, 3, 17, 'Parce que tu dis: Je suis riche, je me suis enrichi, et je n''ai besoin de rien, et parce que tu ne sais pas que tu es malheureux, misérable, pauvre, aveugle et nu,'),
  (66, 3, 18, 'je te conseille d''acheter de moi de l''or éprouvé par le feu, afin que tu deviennes riche, et des vêtements blancs, afin que tu sois vêtu et que la honte de ta nudité ne paraisse pas, et un collyre pour oindre tes yeux, afin que tu voies.'),
  (66, 3, 19, 'Moi, je reprends et je châtie tous ceux que j''aime. Aie donc du zèle, et repens-toi.'),
  (66, 3, 20, 'Voici, je me tiens à la porte, et je frappe. Si quelqu''un entend ma voix et ouvre la porte, j''entrerai chez lui, je souperai avec lui, et lui avec moi.'),
  (66, 3, 21, 'Celui qui vaincra, je le ferai asseoir avec moi sur mon trône, comme moi j''ai vaincu et me suis assis avec mon Père sur son trône.'),
  (66, 3, 22, 'Que celui qui a des oreilles entende ce que l''Esprit dit aux Églises!'),
  (66, 4, 1, 'Après cela, je regardai, et voici, une porte était ouverte dans le ciel. La première voix que j''avais entendue, comme le son d''une trompette, et qui me parlait, dit: Monte ici, et je te ferai voir ce qui doit arriver dans la suite.'),
  (66, 4, 2, 'Aussitôt je fus ravi en esprit. Et voici, il y avait un trône dans le ciel, et sur ce trône quelqu''un était assis.'),
  (66, 4, 3, 'Celui qui était assis avait l''aspect d''une pierre de jaspe et de sardoine; et le trône était environné d''un arc-en-ciel semblable à de l''émeraude.'),
  (66, 4, 4, 'Autour du trône je vis vingt-quatre trônes, et sur ces trônes vingt-quatre vieillards assis, revêtus de vêtements blancs, et sur leurs têtes des couronnes d''or.'),
  (66, 4, 5, 'Du trône sortent des éclairs, des voix et des tonnerres. Devant le trône brûlent sept lampes ardentes, qui sont les sept esprits de Dieu.'),
  (66, 4, 6, 'Il y a encore devant le trône comme une mer de verre, semblable à du cristal. Au milieu du trône et autour du trône, il y a quatre êtres vivants remplis d''yeux devant et derrière.'),
  (66, 4, 7, 'Le premier être vivant est semblable à un lion, le second être vivant est semblable à un veau, le troisième être vivant a la face d''un homme, et le quatrième être vivant est semblable à un aigle qui vole.'),
  (66, 4, 8, 'Les quatre êtres vivants ont chacun six ailes, et ils sont remplis d''yeux tout autour et au dedans. Ils ne cessent de dire jour et nuit: Saint, saint, saint est le Seigneur Dieu, le Tout-Puissant, qui était, qui est, et qui vient!'),
  (66, 4, 9, 'Quand les êtres vivants rendent gloire et honneur et actions de grâces à celui qui est assis sur le trône, à celui qui vit aux siècles des siècles,'),
  (66, 4, 10, 'les vingt-quatre vieillards se prosternent devant celui qui est assis sur le trône, et ils adorent celui qui vit aux siècles des siècles, et ils jettent leurs couronnes devant le trône, en disant:'),
  (66, 4, 11, 'Tu es digne, notre Seigneur et notre Dieu, de recevoir la gloire et l''honneur et la puissance; car tu as créé toutes choses, et c''est par ta volonté qu''elles existent et qu''elles ont été créées.'),
  (66, 5, 1, 'Puis je vis dans la main droite de celui qui était assis sur le trône un livre écrit en dedans et en dehors, scellé de sept sceaux.'),
  (66, 5, 2, 'Et je vis un ange puissant, qui criait d''une voix forte: Qui est digne d''ouvrir le livre, et d''en rompre les sceaux?'),
  (66, 5, 3, 'Et personne dans le ciel, ni sur la terre, ni sous la terre, ne put ouvrir le livre ni le regarder.'),
  (66, 5, 4, 'Et je pleurai beaucoup de ce que personne ne fut trouvé digne d''ouvrir le livre ni de le regarder.'),
  (66, 5, 5, 'Et l''un des vieillards me dit: Ne pleure point; voici, le lion de la tribu de Juda, le rejeton de David, a vaincu pour ouvrir le livre et ses sept sceaux.'),
  (66, 5, 6, 'Et je vis, au milieu du trône et des quatre êtres vivants et au milieu des vieillards, un agneau qui était là comme immolé. Il avait sept cornes et sept yeux, qui sont les sept esprits de Dieu envoyés par toute la terre.'),
  (66, 5, 7, 'Il vint, et il prit le livre de la main droite de celui qui était assis sur le trône.'),
  (66, 5, 8, 'Quand il eut pris le livre, les quatre êtres vivants et les vingt-quatre vieillards se prosternèrent devant l''agneau, tenant chacun une harpe et des coupes d''or remplies de parfums, qui sont les prières des saints.'),
  (66, 5, 9, 'Et ils chantaient un cantique nouveau, en disant: Tu es digne de prendre le livre, et d''en ouvrir les sceaux; car tu as été immolé, et tu as racheté pour Dieu par ton sang des hommes de toute tribu, de toute langue, de tout peuple, et de toute nation;'),
  (66, 5, 10, 'tu as fait d''eux un royaume et des sacrificateurs pour notre Dieu, et ils régneront sur la terre.'),
  (66, 5, 11, 'Je regardai, et j''entendis la voix de beaucoup d''anges autour du trône et des êtres vivants et des vieillards, et leur nombre était des myriades de myriades et des milliers de milliers.'),
  (66, 5, 12, 'Ils disaient d''une voix forte: L''agneau qui a été immolé est digne de recevoir la puissance, la richesse, la sagesse, la force, l''honneur, la gloire, et la louange.'),
  (66, 5, 13, 'Et toutes les créatures qui sont dans le ciel, sur la terre, sous la terre, sur la mer, et tout ce qui s''y trouve, je les entendis qui disaient: A celui qui est assis sur le trône, et à l''agneau, soient la louange, l''honneur, la gloire, et la force, aux siècles des siècles!'),
  (66, 5, 14, 'Et les quatre êtres vivants disaient: Amen! Et les vieillards se prosternèrent et adorèrent.'),
  (66, 6, 1, 'Je regardai, quand l''agneau ouvrit un des sept sceaux, et j''entendis l''un des quatre êtres vivants qui disait comme d''une voix de tonnerre: Viens.'),
  (66, 6, 2, 'Je regardai, et voici, parut un cheval blanc. Celui qui le montait avait un arc; une couronne lui fut donnée, et il partit en vainqueur et pour vaincre.'),
  (66, 6, 3, 'Quand il ouvrit le second sceau, j''entendis le second être vivant qui disait: Viens.'),
  (66, 6, 4, 'Et il sortit un autre cheval, roux. Celui qui le montait reçut le pouvoir d''enlever la paix de la terre, afin que les hommes s''égorgeassent les uns les autres; et une grande épée lui fut donnée.'),
  (66, 6, 5, 'Quand il ouvrit le troisième sceau, j''entendis le troisième être vivant qui disait: Viens. Je regardai, et voici, parut un cheval noir. Celui qui le montait tenait une balance dans sa main.'),
  (66, 6, 6, 'Et j''entendis au milieu des quatre êtres vivants une voix qui disait: Une mesure de blé pour un denier, et trois mesures d''orge pour un denier; mais ne fais point de mal à l''huile et au vin.'),
  (66, 6, 7, 'Quand il ouvrit le quatrième sceau, j''entendis la voix du quatrième être vivant qui disait: Viens.'),
  (66, 6, 8, 'Je regardai, et voici, parut un cheval d''une couleur pâle. Celui qui le montait se nommait la mort, et le séjour des morts l''accompagnait. Le pouvoir leur fut donné sur le quart de la terre, pour faire périr les hommes par l''épée, par la famine, par la mortalité, et par les bêtes sauvages de la terre.'),
  (66, 6, 9, 'Quand il ouvrit le cinquième sceau, je vis sous l''autel les âmes de ceux qui avaient été immolés à cause de la parole de Dieu et à cause du témoignage qu''ils avaient rendu.'),
  (66, 6, 10, 'Ils crièrent d''une voix forte, en disant: Jusques à quand, Maître saint et véritable, tardes-tu à juger, et à tirer vengeance de notre sang sur les habitants de la terre?'),
  (66, 6, 11, 'Une robe blanche fut donnée à chacun d''eux; et il leur fut dit de se tenir en repos quelque temps encore, jusqu''à ce que fût complet le nombre de leurs compagnons de service et de leurs frères qui devaient être mis à mort comme eux.'),
  (66, 6, 12, 'Je regardai, quand il ouvrit le sixième sceau; et il y eut un grand tremblement de terre, le soleil devint noir comme un sac de crin, la lune entière devint comme du sang,'),
  (66, 6, 13, 'et les étoiles du ciel tombèrent sur la terre, comme lorsqu''un figuier secoué par un vent violent jette ses figues vertes.'),
  (66, 6, 14, 'Le ciel se retira comme un livre qu''on roule; et toutes les montagnes et les îles furent remuées de leurs places.'),
  (66, 6, 15, 'Les rois de la terre, les grands, les chefs militaires, les riches, les puissants, tous les esclaves et les hommes libres, se cachèrent dans les cavernes et dans les rochers des montagnes.'),
  (66, 6, 16, 'Et ils disaient aux montagnes et aux rochers: Tombez sur nous, et cachez-nous devant la face de celui qui est assis sur le trône, et devant la colère de l''agneau;'),
  (66, 6, 17, 'car le grand jour de sa colère est venu, et qui peut subsister?'),
  (66, 7, 1, 'Après cela, je vis quatre anges debout aux quatre coins de la terre; ils retenaient les quatre vents de la terre, afin qu''il ne soufflât point de vent sur la terre, ni sur la mer, ni sur aucun arbre.'),
  (66, 7, 2, 'Et je vis un autre ange, qui montait du côté du soleil levant, et qui tenait le sceau du Dieu vivant; il cria d''une voix forte aux quatre anges à qui il avait été donné de faire du mal à la terre et à la mer,'),
  (66, 7, 3, 'et il dit: Ne faites point de mal à la terre, ni à la mer, ni aux arbres, jusqu''à ce que nous ayons marqué du sceau le front des serviteurs de notre Dieu.'),
  (66, 7, 4, 'Et j''entendis le nombre de ceux qui avaient été marqués du sceau, cent quarante-quatre mille, de toutes les tribus des fils d''Israël:'),
  (66, 7, 5, 'de la tribu de Juda, douze mille marqués du sceau; de la tribu de Ruben, douze mille; de la tribu de Gad, douze mille;'),
  (66, 7, 6, 'de la tribu d''Aser, douze mille; de la tribu de Nephthali, douze mille; de la tribu de Manassé, douze mille;'),
  (66, 7, 7, 'de la tribu de Siméon, douze mille; de la tribu de Lévi, douze mille; de la tribu d''Issacar, douze mille;'),
  (66, 7, 8, 'de la tribu de Zabulon, douze mille; de la tribu de Joseph, douze mille; de la tribu de Benjamin, douze mille marqués du sceau.'),
  (66, 7, 9, 'Après cela, je regardai, et voici, il y avait une grande foule, que personne ne pouvait compter, de toute nation, de toute tribu, de tout peuple, et de toute langue. Ils se tenaient devant le trône et devant l''agneau, revêtus de robes blanches, et des palmes dans leurs mains.'),
  (66, 7, 10, 'Et ils criaient d''une voix forte, en disant: Le salut est à notre Dieu qui est assis sur le trône, et à l''agneau.'),
  (66, 7, 11, 'Et tous les anges se tenaient autour du trône et des vieillards et des quatre êtres vivants; et ils se prosternèrent sur leurs faces devant le trône, et ils adorèrent Dieu,'),
  (66, 7, 12, 'en disant: Amen! La louange, la gloire, la sagesse, l''action de grâces, l''honneur, la puissance, et la force, soient à notre Dieu, aux siècles des siècles! Amen!'),
  (66, 7, 13, 'Et l''un des vieillards prit la parole et me dit: Ceux qui sont revêtus de robes blanches, qui sont-ils, et d''où sont-ils venus?'),
  (66, 7, 14, 'Je lui dis: Mon seigneur, tu le sais. Et il me dit: Ce sont ceux qui viennent de la grande tribulation; ils ont lavé leurs robes, et ils les ont blanchies dans le sang de l''agneau.'),
  (66, 7, 15, 'C''est pour cela qu''ils sont devant le trône de Dieu, et le servent jour et nuit dans son temple. Celui qui est assis sur le trône dressera sa tente sur eux;'),
  (66, 7, 16, 'ils n''auront plus faim, ils n''auront plus soif, et le soleil ne les frappera point, ni aucune chaleur.'),
  (66, 7, 17, 'Car l''agneau qui est au milieu du trône les paîtra et les conduira aux sources des eaux de la vie, et Dieu essuiera toute larme de leurs yeux.'),
  (66, 8, 1, 'Quand il ouvrit le septième sceau, il y eut dans le ciel un silence d''environ une demi-heure.'),
  (66, 8, 2, 'Et je vis les sept anges qui se tiennent devant Dieu, et sept trompettes leur furent données.'),
  (66, 8, 3, 'Et un autre ange vint, et il se tint sur l''autel, ayant un encensoir d''or; on lui donna beaucoup de parfums, afin qu''il les offrît, avec les prières de tous les saints, sur l''autel d''or qui est devant le trône.'),
  (66, 8, 4, 'La fumée des parfums monta, avec les prières des saints, de la main de l''ange devant Dieu.'),
  (66, 8, 5, 'Et l''ange prit l''encensoir, le remplit du feu de l''autel, et le jeta sur la terre. Et il y eut des voix, des tonnerres, des éclairs, et un tremblement de terre.'),
  (66, 8, 6, 'Et les sept anges qui avaient les sept trompettes se préparèrent à en sonner.'),
  (66, 8, 7, 'Le premier sonna de la trompette. Et il y eut de la grêle et du feu mêlés de sang, qui furent jetés sur la terre; et le tiers de la terre fut brûlé, et le tiers des arbres fut brûlé, et toute herbe verte fut brûlée.'),
  (66, 8, 8, 'Le second ange sonna de la trompette. Et quelque chose comme une grande montagne embrasée par le feu fut jeté dans la mer; et le tiers de la mer devint du sang,'),
  (66, 8, 9, 'et le tiers des créatures qui étaient dans la mer et qui avaient vie mourut, et le tiers des navires périt.'),
  (66, 8, 10, 'Le troisième ange sonna de la trompette. Et il tomba du ciel une grande étoile ardente comme un flambeau; et elle tomba sur le tiers des fleuves et sur les sources des eaux.'),
  (66, 8, 11, 'Le nom de cette étoile est Absinthe; et le tiers des eaux fut changé en absinthe, et beaucoup d''hommes moururent par les eaux, parce qu''elles étaient devenues amères.'),
  (66, 8, 12, 'Le quatrième ange sonna de la trompette. Et le tiers du soleil fut frappé, et le tiers de la lune, et le tiers des étoiles, afin que le tiers en fût obscurci, et que le jour perdît un tiers de sa clarté, et la nuit de même.'),
  (66, 8, 13, 'Je regardai, et j''entendis un aigle qui volait au milieu du ciel, disant d''une voix forte: Malheur, malheur, malheur aux habitants de la terre, à cause des autres sons de la trompette des trois anges qui vont sonner!'),
  (66, 9, 1, 'Le cinquième ange sonna de la trompette. Et je vis une étoile qui était tombée du ciel sur la terre. La clef du puits de l''abîme lui fut donnée,'),
  (66, 9, 2, 'et elle ouvrit le puits de l''abîme. Et il monta du puits une fumée, comme la fumée d''une grande fournaise; et le soleil et l''air furent obscurcis par la fumée du puits.'),
  (66, 9, 3, 'De la fumée sortirent des sauterelles, qui se répandirent sur la terre; et il leur fut donné un pouvoir comme le pouvoir qu''ont les scorpions de la terre.'),
  (66, 9, 4, 'Il leur fut dit de ne point faire de mal à l''herbe de la terre, ni à aucune verdure, ni à aucun arbre, mais seulement aux hommes qui n''avaient pas le sceau de Dieu sur le front.'),
  (66, 9, 5, 'Il leur fut donné, non de les tuer, mais de les tourmenter pendant cinq mois; et le tourment qu''elles causaient était comme le tourment que cause le scorpion, quand il pique un homme.'),
  (66, 9, 6, 'En ces jours-là, les hommes chercheront la mort, et ils ne la trouveront pas; ils désireront mourir, et la mort fuira loin d''eux.'),
  (66, 9, 7, 'Ces sauterelles ressemblaient à des chevaux préparés pour le combat; il y avait sur leurs têtes comme des couronnes semblables à de l''or, et leurs visages étaient comme des visages d''hommes.'),
  (66, 9, 8, 'Elles avaient des cheveux comme des cheveux de femmes, et leurs dents étaient comme des dents de lions.'),
  (66, 9, 9, 'Elles avaient des cuirasses comme des cuirasses de fer, et le bruit de leurs ailes était comme un bruit de chars à plusieurs chevaux qui courent au combat.'),
  (66, 9, 10, 'Elles avaient des queues semblables à des scorpions et des aiguillons, et c''est dans leurs queues qu''était le pouvoir de faire du mal aux hommes pendant cinq mois.'),
  (66, 9, 11, 'Elles avaient sur elles comme roi l''ange de l''abîme, nommé en hébreu Abaddon, et en grec Apollyon.'),
  (66, 9, 12, 'Le premier malheur est passé. Voici il vient encore deux malheurs après cela.'),
  (66, 9, 13, 'Le sixième ange sonna de la trompette. Et j''entendis une voix venant des quatre cornes de l''autel d''or qui est devant Dieu,'),
  (66, 9, 14, 'et disant au sixième ange qui avait la trompette: Délie les quatre anges qui sont liés sur le grand fleuve d''Euphrate.'),
  (66, 9, 15, 'Et les quatre anges qui étaient prêts pour l''heure, le jour, le mois et l''année, furent déliés afin qu''ils tuassent le tiers des hommes.'),
  (66, 9, 16, 'Le nombre des cavaliers de l''armée était de deux myriades de myriades: j''en entendis le nombre.'),
  (66, 9, 17, 'Et ainsi je vis les chevaux dans la vision, et ceux qui les montaient, ayant des cuirasses couleur de feu, d''hyacinthe, et de soufre. Les têtes des chevaux étaient comme des têtes de lions; et de leurs bouches il sortait du feu, de la fumée, et du soufre.'),
  (66, 9, 18, 'Le tiers des hommes fut tué par ces trois fléaux, par le feu, par la fumée, et par le soufre, qui sortaient de leurs bouches.'),
  (66, 9, 19, 'Car le pouvoir des chevaux était dans leurs bouches et dans leurs queues; leurs queues étaient semblables à des serpents ayant des têtes, et c''est avec elles qu''ils faisaient du mal.'),
  (66, 9, 20, 'Les autres hommes qui ne furent pas tués par ces fléaux ne se repentirent pas des œuvres de leurs mains, de manière à ne point adorer les démons, et les idoles d''or, d''argent, d''airain, de pierre et de bois, qui ne peuvent ni voir, ni entendre, ni marcher;'),
  (66, 9, 21, 'et ils ne se repentirent pas de leurs meurtres, ni de leurs enchantements, ni de leur impudicité ni de leurs vols.'),
  (66, 10, 1, 'Je vis un autre ange puissant, qui descendait du ciel, enveloppé d''une nuée; au-dessus de sa tête était l''arc-en-ciel, et son visage était comme le soleil, et ses pieds comme des colonnes de feu.'),
  (66, 10, 2, 'Il tenait dans sa main un petit livre ouvert. Il posa son pied droit sur la mer, et son pied gauche sur la terre;'),
  (66, 10, 3, 'et il cria d''une voix forte, comme rugit un lion. Quand il cria, les sept tonnerres firent entendre leurs voix.'),
  (66, 10, 4, 'Et quand les sept tonnerres eurent fait entendre leurs voix, j''allais écrire; et j''entendis du ciel une voix qui disait: Scelle ce qu''ont dit les sept tonnerres, et ne l''écris pas.'),
  (66, 10, 5, 'Et l''ange, que je voyais debout sur la mer et sur la terre, leva sa main droite vers le ciel,'),
  (66, 10, 6, 'et jura par celui qui vit aux siècles des siècles, qui a créé le ciel et les choses qui y sont, la terre et les choses qui y sont, et la mer et les choses qui y sont, qu''il n''y aurait plus de temps,'),
  (66, 10, 7, 'mais qu''aux jours de la voix du septième ange, quand il sonnerait de la trompette, le mystère de Dieu s''accomplirait, comme il l''a annoncé à ses serviteurs, les prophètes.'),
  (66, 10, 8, 'Et la voix, que j''avais entendue du ciel, me parla de nouveau, et dit: Va, prends le petit livre ouvert dans la main de l''ange qui se tient debout sur la mer et sur la terre.'),
  (66, 10, 9, 'Et j''allai vers l''ange, en lui disant de me donner le petit livre. Et il me dit: Prends-le, et avale-le; il sera amer à tes entrailles, mais dans ta bouche il sera doux comme du miel.'),
  (66, 10, 10, 'Je pris le petit livre de la main de l''ange, et je l''avalai; il fut dans ma bouche doux comme du miel, mais quand je l''eus avalé, mes entrailles furent remplies d''amertume.'),
  (66, 10, 11, 'Puis on me dit: Il faut que tu prophétises de nouveau sur beaucoup de peuples, de nations, de langues, et de rois.'),
  (66, 11, 1, 'On me donna un roseau semblable à une verge, en disant: Lève-toi, et mesure le temple de Dieu, l''autel, et ceux qui y adorent.'),
  (66, 11, 2, 'Mais le parvis extérieur du temple, laisse-le en dehors, et ne le mesure pas; car il a été donné aux nations, et elles fouleront aux pieds la ville sainte pendant quarante-deux mois.'),
  (66, 11, 3, 'Je donnerai à mes deux témoins le pouvoir de prophétiser, revêtus de sacs, pendant mille deux cent soixante jours.'),
  (66, 11, 4, 'Ce sont les deux oliviers et les deux chandeliers qui se tiennent devant le Seigneur de la terre.'),
  (66, 11, 5, 'Si quelqu''un veut leur faire du mal, du feu sort de leur bouche et dévore leurs ennemis; et si quelqu''un veut leur faire du mal, il faut qu''il soit tué de cette manière.'),
  (66, 11, 6, 'Ils ont le pouvoir de fermer le ciel, afin qu''il ne tombe point de pluie pendant les jours de leur prophétie; et ils ont le pouvoir de changer les eaux en sang, et de frapper la terre de toute espèce de plaie, chaque fois qu''ils le voudront.'),
  (66, 11, 7, 'Quand ils auront achevé leur témoignage, la bête qui monte de l''abîme leur fera la guerre, les vaincra, et les tuera.'),
  (66, 11, 8, 'Et leurs cadavres seront sur la place de la grande ville, qui est appelée, dans un sens spirituel, Sodome et Égypte, là même où leur Seigneur a été crucifié.'),
  (66, 11, 9, 'Des hommes d''entre les peuples, les tribus, les langues, et les nations, verront leurs cadavres pendant trois jours et demi, et ils ne permettront pas que leurs cadavres soient mis dans un sépulcre.'),
  (66, 11, 10, 'Et à cause d''eux les habitants de la terre se réjouiront et seront dans l''allégresse, et ils s''enverront des présents les uns aux autres, parce que ces deux prophètes ont tourmenté les habitants de la terre.'),
  (66, 11, 11, 'Après les trois jours et demi, un esprit de vie, venant de Dieu, entra en eux, et ils se tinrent sur leurs pieds; et une grande crainte s''empara de ceux qui les voyaient.'),
  (66, 11, 12, 'Et ils entendirent du ciel une voix qui leur disait: Montez ici! Et ils montèrent au ciel dans la nuée; et leurs ennemis les virent.'),
  (66, 11, 13, 'A cette heure-là, il y eut un grand tremblement de terre, et la dixième partie de la ville, tomba; sept mille hommes furent tués dans ce tremblement de terre, et les autres furent effrayés et donnèrent gloire au Dieu du ciel.'),
  (66, 11, 14, 'Le second malheur est passé. Voici, le troisième malheur vient bientôt.'),
  (66, 11, 15, 'Le septième ange sonna de la trompette. Et il y eut dans le ciel de fortes voix qui disaient: Le royaume du monde est remis à notre Seigneur et à son Christ; et il régnera aux siècles des siècles.'),
  (66, 11, 16, 'Et les vingt-quatre vieillards, qui étaient assis devant Dieu sur leurs trônes, se prosternèrent sur leurs faces, et ils adorèrent Dieu,'),
  (66, 11, 17, 'en disant: Nous te rendons grâces, Seigneur Dieu tout-puissant, qui es, et qui étais, de ce que tu as saisi ta grande puissance et pris possession de ton règne.'),
  (66, 11, 18, 'Les nations se sont irritées; et ta colère est venue, et le temps est venu de juger les morts, de récompenser tes serviteurs les prophètes, les saints et ceux qui craignent ton nom, les petits et les grands, et de détruire ceux qui détruisent la terre.'),
  (66, 11, 19, 'Et le temple de Dieu dans le ciel fut ouvert, et l''arche de son alliance apparut dans son temple. Et il y eut des éclairs, des voix, des tonnerres, un tremblement de terre, et une forte grêle.'),
  (66, 12, 1, 'Un grand signe parut dans le ciel: une femme enveloppée du soleil, la lune sous ses pieds, et une couronne de douze étoiles sur sa tête.'),
  (66, 12, 2, 'Elle était enceinte, et elle criait, étant en travail et dans les douleurs de l''enfantement.'),
  (66, 12, 3, 'Un autre signe parut encore dans le ciel; et voici, c''était un grand dragon rouge, ayant sept têtes et dix cornes, et sur ses têtes sept diadèmes.'),
  (66, 12, 4, 'Sa queue entraînait le tiers des étoiles du ciel, et les jetait sur la terre. Le dragon se tint devant la femme qui allait enfanter, afin de dévorer son enfant, lorsqu''elle aurait enfanté.'),
  (66, 12, 5, 'Elle enfanta un fils, qui doit paître toutes les nations avec une verge de fer. Et son enfant fut enlevé vers Dieu et vers son trône.'),
  (66, 12, 6, 'Et la femme s''enfuit dans le désert, où elle avait un lieu préparé par Dieu, afin qu''elle y fût nourrie pendant mille deux cent soixante jours.'),
  (66, 12, 7, 'Et il y eut guerre dans le ciel. Michel et ses anges combattirent contre le dragon. Et le dragon et ses anges combattirent,'),
  (66, 12, 8, 'mais ils ne furent pas les plus forts, et leur place ne fut plus trouvée dans le ciel.'),
  (66, 12, 9, 'Et il fut précipité, le grand dragon, le serpent ancien, appelé le diable et Satan, celui qui séduit toute la terre, il fut précipité sur la terre, et ses anges furent précipités avec lui.'),
  (66, 12, 10, 'Et j''entendis dans le ciel une voix forte qui disait: Maintenant le salut est arrivé, et la puissance, et le règne de notre Dieu, et l''autorité de son Christ; car il a été précipité, l''accusateur de nos frères, celui qui les accusait devant notre Dieu jour et nuit.'),
  (66, 12, 11, 'Ils l''ont vaincu à cause du sang de l''agneau et à cause de la parole de leur témoignage, et ils n''ont pas aimé leur vie jusqu''à craindre la mort.'),
  (66, 12, 12, 'C''est pourquoi réjouissez-vous, cieux, et vous qui habitez dans les cieux. Malheur à la terre et à la mer! car le diable est descendu vers vous, animé d''une grande colère, sachant qu''il a peu de temps.'),
  (66, 12, 13, 'Quand le dragon vit qu''il avait été précipité sur la terre, il poursuivit la femme qui avait enfanté l''enfant mâle.'),
  (66, 12, 14, 'Et les deux ailes du grand aigle furent données à la femme, afin qu''elle s''envolât au désert, vers son lieu, où elle est nourrie un temps, des temps, et la moitié d''un temps, loin de la face du serpent.'),
  (66, 12, 15, 'Et, de sa bouche, le serpent lança de l''eau comme un fleuve derrière la femme, afin de l''entraîner par le fleuve.'),
  (66, 12, 16, 'Et la terre secourut la femme, et la terre ouvrit sa bouche et engloutit le fleuve que le dragon avait lancé de sa bouche.'),
  (66, 12, 17, 'Et le dragon fut irrité contre la femme, et il s''en alla faire la guerre aux restes de sa postérité, à ceux qui gardent les commandements de Dieu et qui ont le témoignage de Jésus.'),
  (66, 13, 1, 'Et il se tint sur le sable de la mer. Puis je vis monter de la mer une bête qui avait dix cornes et sept têtes, et sur ses cornes dix diadèmes, et sur ses têtes des noms de blasphème.'),
  (66, 13, 2, 'La bête que je vis était semblable à un léopard; ses pieds étaient comme ceux d''un ours, et sa gueule comme une gueule de lion. Le dragon lui donna sa puissance, et son trône, et une grande autorité.'),
  (66, 13, 3, 'Et je vis l''une de ses têtes comme blessée à mort; mais sa blessure mortelle fut guérie. Et toute la terre était dans l''admiration derrière la bête.'),
  (66, 13, 4, 'Et ils adorèrent le dragon, parce qu''il avait donné l''autorité à la bête; ils adorèrent la bête, en disant: Qui est semblable à la bête, et qui peut combattre contre elle?'),
  (66, 13, 5, 'Et il lui fut donné une bouche qui proférait des paroles arrogantes et des blasphèmes; et il lui fut donné le pouvoir d''agir pendant quarante-deux mois.'),
  (66, 13, 6, 'Et elle ouvrit sa bouche pour proférer des blasphèmes contre Dieu, pour blasphémer son nom, et son tabernacle, et ceux qui habitent dans le ciel.'),
  (66, 13, 7, 'Et il lui fut donné de faire la guerre aux saints, et de les vaincre. Et il lui fut donné autorité sur toute tribu, tout peuple, toute langue, et toute nation.'),
  (66, 13, 8, 'Et tous les habitants de la terre l''adoreront, ceux dont le nom n''a pas été écrit dès la fondation du monde dans le livre de vie de l''agneau qui a été immolé.'),
  (66, 13, 9, 'Si quelqu''un a des oreilles, qu''il entende!'),
  (66, 13, 10, 'Si quelqu''un mène en captivité, il ira en captivité; si quelqu''un tue par l''épée, il faut qu''il soit tué par l''épée. C''est ici la persévérance et la foi des saints.'),
  (66, 13, 11, 'Puis je vis monter de la terre une autre bête, qui avait deux cornes semblables à celles d''un agneau, et qui parlait comme un dragon.'),
  (66, 13, 12, 'Elle exerçait toute l''autorité de la première bête en sa présence, et elle faisait que la terre et ses habitants adoraient la première bête, dont la blessure mortelle avait été guérie.'),
  (66, 13, 13, 'Elle opérait de grands prodiges, même jusqu''à faire descendre du feu du ciel sur la terre, à la vue des hommes.'),
  (66, 13, 14, 'Et elle séduisait les habitants de la terre par les prodiges qu''il lui était donné d''opérer en présence de la bête, disant aux habitants de la terre de faire une image à la bête qui avait la blessure de l''épée et qui vivait.'),
  (66, 13, 15, 'Et il lui fut donné d''animer l''image de la bête, afin que l''image de la bête parlât, et qu''elle fît que tous ceux qui n''adoreraient pas l''image de la bête fussent tués.'),
  (66, 13, 16, 'Et elle fit que tous, petits et grands, riches et pauvres, libres et esclaves, reçussent une marque sur leur main droite ou sur leur front,'),
  (66, 13, 17, 'et que personne ne pût acheter ni vendre, sans avoir la marque, le nom de la bête ou le nombre de son nom.'),
  (66, 13, 18, 'C''est ici la sagesse. Que celui qui a de l''intelligence calcule le nombre de la bête. Car c''est un nombre d''homme, et son nombre est six cent soixante-six.'),
  (66, 14, 1, 'Je regardai, et voici, l''agneau se tenait sur la montagne de Sion, et avec lui cent quarante-quatre mille personnes, qui avaient son nom et le nom de son Père écrits sur leurs fronts.'),
  (66, 14, 2, 'Et j''entendis du ciel une voix, comme un bruit de grosses eaux, comme le bruit d''un grand tonnerre; et la voix que j''entendis était comme celle de joueurs de harpes jouant de leurs harpes.'),
  (66, 14, 3, 'Et ils chantaient un cantique nouveau devant le trône, et devant les quatre êtres vivants et les vieillards. Et personne ne pouvait apprendre le cantique, si ce n''est les cent quarante-quatre mille, qui avaient été rachetés de la terre.'),
  (66, 14, 4, 'Ce sont ceux qui ne se sont pas souillés avec des femmes, car ils sont vierges; ils suivent l''agneau partout où il va. Ils ont été rachetés d''entre les hommes, comme des prémices pour Dieu et pour l''agneau;'),
  (66, 14, 5, 'et dans leur bouche il ne s''est point trouvé de mensonge, car ils sont irrépréhensibles.'),
  (66, 14, 6, 'Je vis un autre ange qui volait par le milieu du ciel, ayant un Évangile éternel, pour l''annoncer aux habitants de la terre, à toute nation, à toute tribu, à toute langue, et à tout peuple.'),
  (66, 14, 7, 'Il disait d''une voix forte: Craignez Dieu, et donnez-lui gloire, car l''heure de son jugement est venue; et adorez celui qui a fait le ciel, et la terre, et la mer, et les sources d''eaux.'),
  (66, 14, 8, 'Et un autre, un second ange suivit, en disant: Elle est tombée, elle est tombée, Babylone la grande, qui a abreuvé toutes les nations du vin de la fureur de son impudicité!'),
  (66, 14, 9, 'Et un autre, un troisième ange les suivit, en disant d''une voix forte: Si quelqu''un adore la bête et son image, et reçoit une marque sur son front ou sur sa main,'),
  (66, 14, 10, 'il boira, lui aussi, du vin de la fureur de Dieu, versé sans mélange dans la coupe de sa colère, et il sera tourmenté dans le feu et le soufre, devant les saints anges et devant l''agneau.'),
  (66, 14, 11, 'Et la fumée de leur tourment monte aux siècles des siècles; et ils n''ont de repos ni jour ni nuit, ceux qui adorent la bête et son image, et quiconque reçoit la marque de son nom.'),
  (66, 14, 12, 'C''est ici la persévérance des saints, qui gardent les commandements de Dieu et la foi de Jésus.'),
  (66, 14, 13, 'Et j''entendis du ciel une voix qui disait: Écris: Heureux dès à présent les morts qui meurent dans le Seigneur! Oui, dit l''Esprit, afin qu''ils se reposent de leurs travaux, car leurs œuvres les suivent.'),
  (66, 14, 14, 'Je regardai, et voici, il y avait une nuée blanche, et sur la nuée était assis quelqu''un qui ressemblait à un fils d''homme, ayant sur sa tête une couronne d''or, et dans sa main une faucille tranchante.'),
  (66, 14, 15, 'Et un autre ange sortit du temple, criant d''une voix forte à celui qui était assis sur la nuée: Lance ta faucille, et moissonne; car l''heure de moissonner est venue, car la moisson de la terre est mûre.'),
  (66, 14, 16, 'Et celui qui était assis sur la nuée jeta sa faucille sur la terre. Et la terre fut moissonnée.'),
  (66, 14, 17, 'Et un autre ange sortit du temple qui est dans le ciel, ayant, lui aussi, une faucille tranchante.'),
  (66, 14, 18, 'Et un autre ange, qui avait autorité sur le feu, sortit de l''autel, et s''adressa d''une voix forte à celui qui avait la faucille tranchante, disant: Lance ta faucille tranchante, et vendange les grappes de la vigne de la terre; car les raisins de la terre sont mûrs.'),
  (66, 14, 19, 'Et l''ange jeta sa faucille sur la terre. Et il vendangea la vigne de la terre, et jeta la vendange dans la grande cuve de la colère de Dieu.'),
  (66, 14, 20, 'Et la cuve fut foulée hors de la ville; et du sang sortit de la cuve, jusqu''aux mors des chevaux, sur une étendue de mille six cents stades.'),
  (66, 15, 1, 'Puis je vis dans le ciel un autre signe, grand et admirable: sept anges, qui tenaient sept fléaux, les derniers, car par eux s''accomplit la colère de Dieu.'),
  (66, 15, 2, 'Et je vis comme une mer de verre, mêlée de feu, et ceux qui avaient vaincu la bête, et son image, et le nombre de son nom, debout sur la mer de verre, ayant des harpes de Dieu.'),
  (66, 15, 3, 'Et ils chantent le cantique de Moïse, le serviteur de Dieu, et le cantique de l''agneau, en disant: Tes œuvres sont grandes et admirables, Seigneur Dieu tout-puissant! Tes voies sont justes et véritables, roi des nations!'),
  (66, 15, 4, 'Qui ne craindrait, Seigneur, et ne glorifierait ton nom? Car seul tu es saint. Et toutes les nations viendront, et se prosterneront devant toi, parce que tes jugements ont été manifestés.'),
  (66, 15, 5, 'Après cela, je regardai, et le temple du tabernacle du témoignage fut ouvert dans le ciel.'),
  (66, 15, 6, 'Et les sept anges qui tenaient les sept fléaux sortirent du temple, revêtus d''un lin pur, éclatant, et ayant des ceintures d''or autour de la poitrine.'),
  (66, 15, 7, 'Et l''un des quatre êtres vivants donna aux sept anges sept coupes d''or, pleines de la colère du Dieu qui vit aux siècles des siècles.'),
  (66, 15, 8, 'Et le temple fut rempli de fumée, à cause de la gloire de Dieu et de sa puissance; et personne ne pouvait entrer dans le temple, jusqu''à ce que les sept fléaux des sept anges fussent accomplis.'),
  (66, 16, 1, 'Et j''entendis une voix forte qui venait du temple, et qui disait aux sept anges: Allez, et versez sur la terre les sept coupes de la colère de Dieu.'),
  (66, 16, 2, 'Le premier alla, et il versa sa coupe sur la terre. Et un ulcère malin et douloureux frappa les hommes qui avaient la marque de la bête et qui adoraient son image.'),
  (66, 16, 3, 'Le second versa sa coupe dans la mer. Et elle devint du sang, comme celui d''un mort; et tout être vivant mourut, tout ce qui était dans la mer.'),
  (66, 16, 4, 'Le troisième versa sa coupe dans les fleuves et dans les sources d''eaux. Et ils devinrent du sang.'),
  (66, 16, 5, 'Et j''entendis l''ange des eaux qui disait: Tu es juste, toi qui es, et qui étais; tu es saint, parce que tu as exercé ce jugement.'),
  (66, 16, 6, 'Car ils ont versé le sang des saints et des prophètes, et tu leur as donné du sang à boire: ils en sont dignes.'),
  (66, 16, 7, 'Et j''entendis l''autel qui disait: Oui, Seigneur Dieu tout-puissant, tes jugements sont véritables et justes.'),
  (66, 16, 8, 'Le quatrième versa sa coupe sur le soleil. Et il lui fut donné de brûler les hommes par le feu;'),
  (66, 16, 9, 'et les hommes furent brûlés par une grande chaleur, et ils blasphémèrent le nom du Dieu qui a l''autorité sur ces fléaux, et ils ne se repentirent pas pour lui donner gloire.'),
  (66, 16, 10, 'Le cinquième versa sa coupe sur le trône de la bête. Et son royaume fut couvert de ténèbres; et les hommes se mordaient la langue de douleur,'),
  (66, 16, 11, 'et ils blasphémèrent le Dieu du ciel, à cause de leurs douleurs et de leurs ulcères, et ils ne se repentirent pas de leurs œuvres.'),
  (66, 16, 12, 'Le sixième versa sa coupe sur le grand fleuve, l''Euphrate. Et son eau tarit, afin que le chemin des rois venant de l''Orient fût préparé.'),
  (66, 16, 13, 'Et je vis sortir de la bouche du dragon, et de la bouche de la bête, et de la bouche du faux prophète, trois esprits impurs, semblables à des grenouilles.'),
  (66, 16, 14, 'Car ce sont des esprits de démons, qui font des prodiges, et qui vont vers les rois de toute la terre, afin de les rassembler pour le combat du grand jour du Dieu tout-puissant.'),
  (66, 16, 15, 'Voici, je viens comme un voleur. Heureux celui qui veille, et qui garde ses vêtements, afin qu''il ne marche pas nu et qu''on ne voie pas sa honte!'),
  (66, 16, 16, 'Ils les rassemblèrent dans le lieu appelé en hébreu Harmaguédon.'),
  (66, 16, 17, 'Le septième versa sa coupe dans l''air. Et il sortit du temple, du trône, une voix forte qui disait: C''en est fait!'),
  (66, 16, 18, 'Et il y eut des éclairs, des voix, des tonnerres, et un grand tremblement de terre, tel qu''il n''y avait jamais eu depuis que l''homme est sur la terre, un aussi grand tremblement.'),
  (66, 16, 19, 'Et la grande ville fut divisée en trois parties, et les villes des nations tombèrent, et Dieu, se souvint de Babylone la grande, pour lui donner la coupe du vin de son ardente colère.'),
  (66, 16, 20, 'Et toutes les îles s''enfuirent, et les montagnes ne furent pas retrouvées.'),
  (66, 16, 21, 'Et une grosse grêle, dont les grêlons pesaient un talent, tomba du ciel sur les hommes; et les hommes blasphémèrent Dieu, à cause du fléau de la grêle, parce que ce fléau était très grand.'),
  (66, 17, 1, 'Puis un des sept anges qui tenaient les sept coupes vint, et il m''adressa la parole, en disant: Viens, je te montrerai le jugement de la grande prostituée qui est assise sur les grandes eaux.'),
  (66, 17, 2, 'C''est avec elle que les rois de la terre se sont livrés à l''impudicité, et c''est du vin de son impudicité que les habitants de la terre se sont enivrés.'),
  (66, 17, 3, 'Il me transporta en esprit dans un désert. Et je vis une femme assise sur une bête écarlate, pleine de noms de blasphème, ayant sept têtes et dix cornes.'),
  (66, 17, 4, 'Cette femme était vêtue de pourpre et d''écarlate, et parée d''or, de pierres précieuses et de perles. Elle tenait dans sa main une coupe d''or, remplie d''abominations et des impuretés de sa prostitution.'),
  (66, 17, 5, 'Sur son front était écrit un nom, un mystère: Babylone la grande, la mère des impudiques et des abominations de la terre.'),
  (66, 17, 6, 'Et je vis cette femme ivre du sang des saints et du sang des témoins de Jésus. Et, en la voyant, je fus saisi d''un grand étonnement.'),
  (66, 17, 7, 'Et l''ange me dit: Pourquoi t''étonnes-tu? Je te dirai le mystère de la femme et de la bête qui la porte, qui a les sept têtes et les dix cornes.'),
  (66, 17, 8, 'La bête que tu as vue était, et elle n''est plus. Elle doit monter de l''abîme, et aller à la perdition. Et les habitants de la terre, ceux dont le nom n''a pas été écrit dès la fondation du monde dans le livre de vie, s''étonneront en voyant la bête, parce qu''elle était, et qu''elle n''est plus, et qu''elle reparaîtra. -'),
  (66, 17, 9, 'C''est ici l''intelligence qui a de la sagesse. -Les sept têtes sont sept montagnes, sur lesquelles la femme est assise.'),
  (66, 17, 10, 'Ce sont aussi sept rois: cinq sont tombés, un existe, l''autre n''est pas encore venu, et quand il sera venu, il doit rester peu de temps.'),
  (66, 17, 11, 'Et la bête qui était, et qui n''est plus, est elle-même un huitième roi, et elle est du nombre des sept, et elle va à la perdition.'),
  (66, 17, 12, 'Les dix cornes que tu as vues sont dix rois, qui n''ont pas encore reçu de royaume, mais qui reçoivent autorité comme rois pendant une heure avec la bête.'),
  (66, 17, 13, 'Ils ont un même dessein, et ils donnent leur puissance et leur autorité à la bête.'),
  (66, 17, 14, 'Ils combattront contre l''agneau, et l''agneau les vaincra, parce qu''il est le Seigneur des seigneurs et le Roi des rois, et les appelés, les élus et les fidèles qui sont avec lui les vaincront aussi.'),
  (66, 17, 15, 'Et il me dit: Les eaux que tu as vues, sur lesquelles la prostituée est assise, ce sont des peuples, des foules, des nations, et des langues.'),
  (66, 17, 16, 'Les dix cornes que tu as vues et la bête haïront la prostituée, la dépouilleront et la mettront à nu, mangeront ses chairs, et la consumeront par le feu.'),
  (66, 17, 17, 'Car Dieu a mis dans leurs cœurs d''exécuter son dessein et d''exécuter un même dessein, et de donner leur royauté à la bête, jusqu''à ce que les paroles de Dieu soient accomplies.'),
  (66, 17, 18, 'Et la femme que tu as vue, c''est la grande ville qui a la royauté sur les rois de la terre.'),
  (66, 18, 1, 'Après cela, je vis descendre du ciel un autre ange, qui avait une grande autorité; et la terre fut éclairée de sa gloire.'),
  (66, 18, 2, 'Il cria d''une voix forte, disant: Elle est tombée, elle est tombée, Babylone la grande! Elle est devenue une habitation de démons, un repaire de tout esprit impur, un repaire de tout oiseau impur et odieux,'),
  (66, 18, 3, 'parce que toutes les nations ont bu du vin de la fureur de son impudicité, et que les rois de la terre se sont livrés avec elle à l''impudicité, et que les marchands de la terre se sont enrichis par la puissance de son luxe.'),
  (66, 18, 4, 'Et j''entendis du ciel une autre voix qui disait: Sortez du milieu d''elle, mon peuple, afin que vous ne participiez point à ses péchés, et que vous n''ayez point de part à ses fléaux.'),
  (66, 18, 5, 'Car ses péchés se sont accumulés jusqu''au ciel, et Dieu s''est souvenu de ses iniquités.'),
  (66, 18, 6, 'Payez-la comme elle a payé, et rendez-lui au double selon ses œuvres. Dans la coupe où elle a versé, versez-lui au double.')
insert into public.bible_verses (book_id, chapter, verse, text) values
  (66, 18, 7, 'Autant elle s''est glorifiée et plongée dans le luxe, autant donnez-lui de tourment et de deuil. Parce qu''elle dit en son cœur: Je suis assise en reine, je ne suis point veuve, et je ne verrai point de deuil!'),
  (66, 18, 8, 'A cause de cela, en un même jour, ses fléaux arriveront, la mort, le deuil et la famine, et elle sera consumée par le feu. Car il est puissant, le Seigneur Dieu qui l''a jugée.'),
  (66, 18, 9, 'Et tous les rois de la terre, qui se sont livrés avec elle à l''impudicité et au luxe, pleureront et se lamenteront à cause d''elle, quand ils verront la fumée de son embrasement.'),
  (66, 18, 10, 'Se tenant éloignés, dans la crainte de son tourment, ils diront: Malheur! malheur! La grande ville, Babylone, la ville puissante! En une seule heure est venu ton jugement!'),
  (66, 18, 11, 'Et les marchands de la terre pleurent et sont dans le deuil à cause d''elle, parce que personne n''achète plus leur cargaison,'),
  (66, 18, 12, 'cargaison d''or, d''argent, de pierres précieuses, de perles, de fin lin, de pourpre, de soie, d''écarlate, de toute espèce de bois de senteur, de toute espèce d''objets d''ivoire, de toute espèce d''objets en bois très précieux, en airain, en fer et en marbre,'),
  (66, 18, 13, 'de cinnamome, d''aromates, de parfums, de myrrhe, d''encens, de vin, d''huile, de fine farine, de blé, de bœufs, de brebis, de chevaux, de chars, de corps et d''âmes d''hommes.'),
  (66, 18, 14, 'Les fruits que désirait ton âme sont allés loin de toi; et toutes les choses délicates et magnifiques sont perdues pour toi, et tu ne les retrouveras plus.'),
  (66, 18, 15, 'Les marchands de ces choses, qui se sont enrichis par elle, se tiendront éloignés, dans la crainte de son tourment; ils pleureront et seront dans le deuil,'),
  (66, 18, 16, 'et diront: Malheur! malheur! La grande ville, qui était vêtue de fin lin, de pourpre et d''écarlate, et parée d''or, de pierres précieuses et de perles!'),
  (66, 18, 17, 'En une seule heure tant de richesses ont été détruites! Et tous les pilotes, tous ceux qui naviguent vers ce lieu, les marins, et tous ceux qui exploitent la mer, se tenaient éloignés,'),
  (66, 18, 18, 'et ils s''écriaient, en voyant la fumée de son embrasement: Quelle ville était semblable à la grande ville?'),
  (66, 18, 19, 'Et ils jetaient de la poussière sur leurs têtes, ils pleuraient et ils étaient dans le deuil, ils criaient et disaient: Malheur! malheur! La grande ville, où se sont enrichis par son opulence tous ceux qui ont des navires sur la mer, en une seule heure elle a été détruite!'),
  (66, 18, 20, 'Ciel, réjouis-toi sur elle! Et vous, les saints, les apôtres, et les prophètes, réjouissez-vous aussi! Car Dieu vous a fait justice en la jugeant.'),
  (66, 18, 21, 'Alors un ange puissant prit une pierre semblable à une grande meule, et il la jeta dans la mer, en disant: Ainsi sera précipitée avec violence Babylone, la grande ville, et elle ne sera plus trouvée.'),
  (66, 18, 22, 'Et l''on n''entendra plus chez toi les sons des joueurs de harpe, des musiciens, des joueurs de flûte et des joueurs de trompette, on ne trouvera plus chez toi aucun artisan d''un métier quelconque, on n''entendra plus chez toi le bruit de la meule,'),
  (66, 18, 23, 'la lumière de la lampe ne brillera plus chez toi, et la voix de l''époux et de l''épouse ne sera plus entendue chez toi, parce que tes marchands étaient les grands de la terre, parce que toutes les nations ont été séduites par tes enchantements,'),
  (66, 18, 24, 'et parce qu''on a trouvé chez elle le sang des prophètes et des saints et de tous ceux qui ont été égorgés sur la terre.'),
  (66, 19, 1, 'Après cela, j''entendis dans le ciel comme une voix forte d''une foule nombreuse qui disait: Alléluia! Le salut, la gloire, et la puissance sont à notre Dieu,'),
  (66, 19, 2, 'parce que ses jugements sont véritables et justes; car il a jugé la grande prostituée qui corrompait la terre par son impudicité, et il a vengé le sang de ses serviteurs en le redemandant de sa main.'),
  (66, 19, 3, 'Et ils dirent une seconde fois: Alléluia!… et sa fumée monte aux siècles des siècles.'),
  (66, 19, 4, 'Et les vingt-quatre vieillards et les quatre êtres vivants se prosternèrent et adorèrent Dieu assis sur le trône, en disant: Amen! Alléluia!'),
  (66, 19, 5, 'Et une voix sortit du trône, disant: Louez notre Dieu, vous tous ses serviteurs, vous qui le craignez, petits et grands!'),
  (66, 19, 6, 'Et j''entendis comme une voix d''une foule nombreuse, comme un bruit de grosses eaux, et comme un bruit de forts tonnerres, disant: Alléluia! Car le Seigneur notre Dieu tout-puissant est entré dans son règne.'),
  (66, 19, 7, 'Réjouissons-nous et soyons dans l''allégresse, et donnons-lui gloire; car les noces de l''agneau sont venues, et son épouse s''est préparée,'),
  (66, 19, 8, 'et il lui a été donné de se revêtir d''un fin lin, éclatant, pur. Car le fin lin, ce sont les œuvres justes des saints.'),
  (66, 19, 9, 'Et l''ange me dit: Écris: Heureux ceux qui sont appelés au festin de noces de l''agneau! Et il me dit: Ces paroles sont les véritables paroles de Dieu.'),
  (66, 19, 10, 'Et je tombai à ses pieds pour l''adorer; mais il me dit: Garde-toi de le faire! Je suis ton compagnon de service, et celui de tes frères qui ont le témoignage de Jésus. Adore Dieu. -Car le témoignage de Jésus est l''esprit de la prophétie.'),
  (66, 19, 11, 'Puis je vis le ciel ouvert, et voici, parut un cheval blanc. Celui qui le montait s''appelle Fidèle et Véritable, et il juge et combat avec justice.'),
  (66, 19, 12, 'Ses yeux étaient comme une flamme de feu; sur sa tête étaient plusieurs diadèmes; il avait un nom écrit, que personne ne connaît, si ce n''est lui-même;'),
  (66, 19, 13, 'et il était revêtu d''un vêtement teint de sang. Son nom est la Parole de Dieu.'),
  (66, 19, 14, 'Les armées qui sont dans le ciel le suivaient sur des chevaux blancs, revêtues d''un fin lin, blanc, pur.'),
  (66, 19, 15, 'De sa bouche sortait une épée aiguë, pour frapper les nations; il les paîtra avec une verge de fer; et il foulera la cuve du vin de l''ardente colère du Dieu tout-puissant.'),
  (66, 19, 16, 'Il avait sur son vêtement et sur sa cuisse un nom écrit: Roi des rois et Seigneur des seigneurs.'),
  (66, 19, 17, 'Et je vis un ange qui se tenait dans le soleil. Et il cria d''une voix forte, disant à tous les oiseaux qui volaient par le milieu du ciel: Venez, rassemblez-vous pour le grand festin de Dieu,'),
  (66, 19, 18, 'afin de manger la chair des rois, la chair des chefs militaires, la chair des puissants, la chair des chevaux et de ceux qui les montent, la chair de tous, libres et esclaves, petits et grands.'),
  (66, 19, 19, 'Et je vis la bête, et les rois de la terre, et leurs armées rassemblées pour faire la guerre à celui qui était assis sur le cheval et à son armée.'),
  (66, 19, 20, 'Et la bête fut prise, et avec elle le faux prophète, qui avait fait devant elle les prodiges par lesquels il avait séduit ceux qui avaient pris la marque de la bête et adoré son image. Ils furent tous les deux jetés vivants dans l''étang ardent de feu et de soufre.'),
  (66, 19, 21, 'Et les autres furent tués par l''épée qui sortait de la bouche de celui qui était assis sur le cheval; et tous les oiseaux se rassasièrent de leur chair.'),
  (66, 20, 1, 'Puis je vis descendre du ciel un ange, qui avait la clef de l''abîme et une grande chaîne dans sa main.'),
  (66, 20, 2, 'Il saisit le dragon, le serpent ancien, qui est le diable et Satan, et il le lia pour mille ans.'),
  (66, 20, 3, 'Il le jeta dans l''abîme, ferma et scella l''entrée au-dessus de lui, afin qu''il ne séduisît plus les nations, jusqu''à ce que les mille ans fussent accomplis. Après cela, il faut qu''il soit délié pour un peu de temps.'),
  (66, 20, 4, 'Et je vis des trônes; et à ceux qui s''y assirent fut donné le pouvoir de juger. Et je vis les âmes de ceux qui avaient été décapités à cause du témoignage de Jésus et à cause de la parole de Dieu, et de ceux qui n''avaient pas adoré la bête ni son image, et qui n''avaient pas reçu la marque sur leur front et sur leur main. Ils revinrent à la vie, et ils régnèrent avec Christ pendant mille ans.'),
  (66, 20, 5, 'Les autres morts ne revinrent point à la vie jusqu''à ce que les mille ans fussent accomplis. C''est la première résurrection.'),
  (66, 20, 6, 'Heureux et saints ceux qui ont part à la première résurrection! La seconde mort n''a point de pouvoir sur eux; mais ils seront sacrificateurs de Dieu et de Christ, et ils régneront avec lui pendant mille ans.'),
  (66, 20, 7, 'Quand les mille ans seront accomplis, Satan sera relâché de sa prison.'),
  (66, 20, 8, 'Et il sortira pour séduire les nations qui sont aux quatre coins de la terre, Gog et Magog, afin de les rassembler pour la guerre; leur nombre est comme le sable de la mer.'),
  (66, 20, 9, 'Et ils montèrent sur la surface de la terre, et ils investirent le camp des saints et la ville bien-aimée. Mais un feu descendit du ciel, et les dévora.'),
  (66, 20, 10, 'Et le diable, qui les séduisait, fut jeté dans l''étang de feu et de soufre, où sont la bête et le faux prophète. Et ils seront tourmentés jour et nuit, aux siècles des siècles.'),
  (66, 20, 11, 'Puis je vis un grand trône blanc, et celui qui était assis dessus. La terre et le ciel s''enfuirent devant sa face, et il ne fut plus trouvé de place pour eux.'),
  (66, 20, 12, 'Et je vis les morts, les grands et les petits, qui se tenaient devant le trône. Des livres furent ouverts. Et un autre livre fut ouvert, celui qui est le livre de vie. Et les morts furent jugés selon leurs œuvres, d''après ce qui était écrit dans ces livres.'),
  (66, 20, 13, 'La mer rendit les morts qui étaient en elle, la mort et le séjour des morts rendirent les morts qui étaient en eux; et chacun fut jugé selon ses œuvres.'),
  (66, 20, 14, 'Et la mort et le séjour des morts furent jetés dans l''étang de feu. C''est la seconde mort, l''étang de feu.'),
  (66, 20, 15, 'Quiconque ne fut pas trouvé écrit dans le livre de vie fut jeté dans l''étang de feu.'),
  (66, 21, 1, 'Puis je vis un nouveau ciel et une nouvelle terre; car le premier ciel et la première terre avaient disparu, et la mer n''était plus.'),
  (66, 21, 2, 'Et je vis descendre du ciel, d''auprès de Dieu, la ville sainte, la nouvelle Jérusalem, préparée comme une épouse qui s''est parée pour son époux.'),
  (66, 21, 3, 'Et j''entendis du trône une forte voix qui disait: Voici le tabernacle de Dieu avec les hommes! Il habitera avec eux, et ils seront son peuple, et Dieu lui-même sera avec eux.'),
  (66, 21, 4, 'Il essuiera toute larme de leurs yeux, et la mort ne sera plus, et il n''y aura plus ni deuil, ni cri, ni douleur, car les premières choses ont disparu.'),
  (66, 21, 5, 'Et celui qui était assis sur le trône dit: Voici, je fais toutes choses nouvelles. Et il dit: Écris; car ces paroles sont certaines et véritables.'),
  (66, 21, 6, 'Et il me dit: C''est fait! Je suis l''alpha et l''oméga, le commencement et la fin. A celui qui a soif je donnerai de la source de l''eau de la vie, gratuitement.'),
  (66, 21, 7, 'Celui qui vaincra héritera ces choses; je serai son Dieu, et il sera mon fils.'),
  (66, 21, 8, 'Mais pour les lâches, les incrédules, les abominables, les meurtriers, les impudiques, les enchanteurs, les idolâtres, et tous les menteurs, leur part sera dans l''étang ardent de feu et de soufre, ce qui est la seconde mort.'),
  (66, 21, 9, 'Puis un des sept anges qui tenaient les sept coupes remplies des sept derniers fléaux vint, et il m''adressa la parole, en disant: Viens, je te montrerai l''épouse, la femme de l''agneau.'),
  (66, 21, 10, 'Et il me transporta en esprit sur une grande et haute montagne. Et il me montra la ville sainte, Jérusalem, qui descendait du ciel d''auprès de Dieu,'),
  (66, 21, 11, 'ayant la gloire de Dieu. Son éclat était semblable à celui d''une pierre très précieuse, d''une pierre de jaspe transparente comme du cristal.'),
  (66, 21, 12, 'Elle avait une grande et haute muraille. Elle avait douze portes, et sur les portes douze anges, et des noms écrits, ceux des douze tribus des fils d''Israël:'),
  (66, 21, 13, 'à l''orient trois portes, au nord trois portes, au midi trois portes, et à l''occident trois portes.'),
  (66, 21, 14, 'La muraille de la ville avait douze fondements, et sur eux les douze noms des douze apôtres de l''agneau.'),
  (66, 21, 15, 'Celui qui me parlait avait pour mesure un roseau d''or, afin de mesurer la ville, ses portes et sa muraille.'),
  (66, 21, 16, 'La ville avait la forme d''un carré, et sa longueur était égale à sa largeur. Il mesura la ville avec le roseau, et trouva douze mille stades; la longueur, la largeur et la hauteur en étaient égales.'),
  (66, 21, 17, 'Il mesura la muraille, et trouva cent quarante-quatre coudées, mesure d''homme, qui était celle de l''ange.'),
  (66, 21, 18, 'La muraille était construite en jaspe, et la ville était d''or pur, semblable à du verre pur.'),
  (66, 21, 19, 'Les fondements de la muraille de la ville étaient ornés de pierres précieuses de toute espèce: le premier fondement était de jaspe, le second de saphir, le troisième de calcédoine, le quatrième d''émeraude,'),
  (66, 21, 20, 'le cinquième de sardonyx, le sixième de sardoine, le septième de chrysolithe, le huitième de béryl, le neuvième de topaze, le dixième de chrysoprase, le onzième d''hyacinthe, le douzième d''améthyste.'),
  (66, 21, 21, 'Les douze portes étaient douze perles; chaque porte était d''une seule perle. La place de la ville était d''or pur, comme du verre transparent.'),
  (66, 21, 22, 'Je ne vis point de temple dans la ville; car le Seigneur Dieu tout-puissant est son temple, ainsi que l''agneau.'),
  (66, 21, 23, 'La ville n''a besoin ni du soleil ni de la lune pour l''éclairer; car la gloire de Dieu l''éclaire, et l''agneau est son flambeau.'),
  (66, 21, 24, 'Les nations marcheront à sa lumière, et les rois de la terre y apporteront leur gloire.'),
  (66, 21, 25, 'Ses portes ne se fermeront point le jour, car là il n''y aura point de nuit.'),
  (66, 21, 26, 'On y apportera la gloire et l''honneur des nations.'),
  (66, 21, 27, 'Il n''entrera chez elle rien de souillé, ni personne qui se livre à l''abomination et au mensonge; il n''entrera que ceux qui sont écrits dans le livre de vie de l''agneau.'),
  (66, 22, 1, 'Et il me montra un fleuve d''eau de la vie, limpide comme du cristal, qui sortait du trône de Dieu et de l''agneau.'),
  (66, 22, 2, 'Au milieu de la place de la ville et sur les deux bords du fleuve, il y avait un arbre de vie, produisant douze fois des fruits, rendant son fruit chaque mois, et dont les feuilles servaient à la guérison des nations.'),
  (66, 22, 3, 'Il n''y aura plus d''anathème. Le trône de Dieu et de l''agneau sera dans la ville; ses serviteurs le serviront'),
  (66, 22, 4, 'et verront sa face, et son nom sera sur leurs fronts.'),
  (66, 22, 5, 'Il n''y aura plus de nuit; et ils n''auront besoin ni de lampe ni de lumière, parce que le Seigneur Dieu les éclairera. Et ils régneront aux siècles des siècles.'),
  (66, 22, 6, 'Et il me dit: Ces paroles sont certaines et véritables; et le Seigneur, le Dieu des esprits des prophètes, a envoyé son ange pour montrer à ses serviteurs les choses qui doivent arriver bientôt.'),
  (66, 22, 7, 'Et voici, je viens bientôt. -Heureux celui qui garde les paroles de la prophétie de ce livre!'),
  (66, 22, 8, 'C''est moi Jean, qui ai entendu et vu ces choses. Et quand j''eus entendu et vu, je tombai aux pieds de l''ange qui me les montrait, pour l''adorer.'),
  (66, 22, 9, 'Mais il me dit: Garde-toi de le faire! Je suis ton compagnon de service, et celui de tes frères les prophètes, et de ceux qui gardent les paroles de ce livre. Adore Dieu.'),
  (66, 22, 10, 'Et il me dit: Ne scelle point les paroles de la prophétie de ce livre. Car le temps est proche.'),
  (66, 22, 11, 'Que celui qui est injuste soit encore injuste, que celui qui est souillé se souille encore; et que le juste pratique encore la justice, et que celui qui est saint se sanctifie encore.'),
  (66, 22, 12, 'Voici, je viens bientôt, et ma rétribution est avec moi, pour rendre à chacun selon ce qu''est son œuvre.'),
  (66, 22, 13, 'Je suis l''alpha et l''oméga, le premier et le dernier, le commencement et la fin.'),
  (66, 22, 14, 'Heureux ceux qui lavent leurs robes, afin d''avoir droit à l''arbre de vie, et d''entrer par les portes dans la ville!'),
  (66, 22, 15, 'Dehors les chiens, les enchanteurs, les impudiques, les meurtriers, les idolâtres, et quiconque aime et pratique le mensonge!'),
  (66, 22, 16, 'Moi, Jésus, j''ai envoyé mon ange pour vous attester ces choses dans les Églises. Je suis le rejeton et la postérité de David, l''étoile brillante du matin.'),
  (66, 22, 17, 'Et l''Esprit et l''épouse disent: Viens. Et que celui qui entend dise: Viens. Et que celui qui a soif vienne; que celui qui veut, prenne de l''eau de la vie, gratuitement.'),
  (66, 22, 18, 'Je le déclare à quiconque entend les paroles de la prophétie de ce livre: Si quelqu''un y ajoute quelque chose, Dieu le frappera des fléaux décrits dans ce livre;'),
  (66, 22, 19, 'et si quelqu''un retranche quelque chose des paroles du livre de cette prophétie, Dieu retranchera sa part de l''arbre de la vie et de la ville sainte, décrits dans ce livre.'),
  (66, 22, 20, 'Celui qui atteste ces choses dit: Oui, je viens bientôt. Amen! Viens, Seigneur Jésus!'),
  (66, 22, 21, 'Que la grâce du Seigneur Jésus soit avec tous!')
